client/src/pages/admin/courses.tsx.content:
import { useAuth } from "@/hooks/useAuth";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { isUnauthorizedError } from "@/lib/authUtils";
import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { 
  BookOpen, 
  Plus, 
  Edit, 
  Trash2, 
  Search, 
  Tag,
  Calendar,
  GripVertical,
  Save,
  X,
  Video,
  Eye
} from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Link } from "wouter";

interface Course {
  id: string;
  title: string;
  slug: string;
  description?: string;
  thumbnail?: string;
  tags: string[];
  order: number;
  createdAt: string;
  updatedAt: string;
}

const courseFormSchema = z.object({
  title: z.string().min(1, "제목을 입력해주세요"),
  slug: z.string().min(1, "슬러그를 입력해주세요").regex(/^[a-z0-9-]+$/, "소문자, 숫자, 하이픈만 사용 가능합니다"),
  description: z.string().optional(),
  thumbnail: z.string().url("올바른 URL을 입력해주세요").optional().or(z.literal("")),
  tags: z.string(),
  order: z.number().min(0, "순서는 0 이상이어야 합니다"),
});

type CourseFormData = z.infer<typeof courseFormSchema>;

export default function AdminCourses() {
  const { user, isAuthenticated, isLoading } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [searchTerm, setSearchTerm] = useState("");
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingCourse, setEditingCourse] = useState<Course | null>(null);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [deletingCourse, setDeletingCourse] = useState<Course | null>(null);

  const form = useForm<CourseFormData>({
    resolver: zodResolver(courseFormSchema),
    defaultValues: {
      title: "",
      slug: "",
      description: "",
      thumbnail: "",
      tags: "",
      order: 0,
    },
  });

  // Redirect if not admin
  useEffect(() => {
    if (!isLoading && (!isAuthenticated || user?.role !== "ADMIN")) {
      toast({
        title: "접근 권한이 없습니다",
        description: "관리자만 접근할 수 있는 페이지입니다.",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/";
      }, 500);
      return;
    }
  }, [isAuthenticated, isLoading, user, toast]);

  const { data: courses = [], isLoading: coursesLoading, error: coursesError } = useQuery<Course[]>({
    queryKey: ["/api/admin/courses"],
    enabled: isAuthenticated && user?.role === "ADMIN",
  });

  // Handle courses query errors
  useEffect(() => {
    if (coursesError && isUnauthorizedError(coursesError as Error)) {
      toast({
        title: "인증이 필요합니다",
        description: "다시 로그인해주세요.",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
    }
  }, [coursesError, toast]);

  const createMutation = useMutation({
    mutationFn: async (data: CourseFormData) => {
      const payload = {
        ...data,
        tags: data.tags.split(",").map(tag => tag.trim()).filter(tag => tag.length > 0),
      };
      await apiRequest("POST", "/api/admin/courses", payload);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/courses"] });
      toast({
        title: "강의 생성 완료",
        description: "새로운 강의가 성공적으로 생성되었습니다.",
      });
      closeDialog();
    },
    onError: (error) => {
      toast({
        title: "생성 실패",
        description: "강의 생성 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  const updateMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: CourseFormData }) => {
      const payload = {
        ...data,
        tags: data.tags.split(",").map(tag => tag.trim()).filter(tag => tag.length > 0),
      };
      await apiRequest("PUT", `/api/admin/courses/${id}`, payload);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/courses"] });
      toast({
        title: "강의 수정 완료",
        description: "강의가 성공적으로 수정되었습니다.",
      });
      closeDialog();
    },
    onError: (error) => {
      toast({
        title: "수정 실패",
        description: "강의 수정 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      await apiRequest("DELETE", `/api/admin/courses/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/courses"] });
      toast({
        title: "강의 삭제 완료",
        description: "강의가 성공적으로 삭제되었습니다.",
      });
      setDeleteDialogOpen(false);
      setDeletingCourse(null);
    },
    onError: (error) => {
      toast({
        title: "삭제 실패",
        description: "강의 삭제 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  const openCreateDialog = () => {
    setEditingCourse(null);
    form.reset({
      title: "",
      slug: "",
      description: "",
      thumbnail: "",
      tags: "",
      order: courses.length,
    });
    setDialogOpen(true);
  };

  const openEditDialog = (course: Course) => {
    setEditingCourse(course);
    form.reset({
      title: course.title,
      slug: course.slug,
      description: course.description || "",
      thumbnail: course.thumbnail || "",
      tags: course.tags.join(", "),
      order: course.order,
    });
    setDialogOpen(true);
  };

  const closeDialog = () => {
    setDialogOpen(false);
    setEditingCourse(null);
    form.reset();
  };

  const openDeleteDialog = (course: Course) => {
    setDeletingCourse(course);
    setDeleteDialogOpen(true);
  };

  const onSubmit = (data: CourseFormData) => {
    if (editingCourse) {
      updateMutation.mutate({ id: editingCourse.id, data });
    } else {
      createMutation.mutate(data);
    }
  };

  // Auto-generate slug from title
  const watchTitle = form.watch("title");
  useEffect(() => {
    if (watchTitle && !editingCourse) {
      const slug = watchTitle
        .toLowerCase()
        .replace(/[^a-z0-9가-힣\s]/g, "")
        .replace(/\s+/g, "-")
        .replace(/[가-힣]/g, (char) => {
          // Simple romanization for Korean characters
          const koreanToRoman: { [key: string]: string } = {
            "토익": "toeic",
            "비즈니스": "business",
            "영어": "english",
            "회화": "conversation",
            "문법": "grammar",
            "리스닝": "listening",
            "리딩": "reading",
            "스피킹": "speaking",
            "라이팅": "writing",
          };
          return koreanToRoman[char] || char;
        })
        .substring(0, 50);
      form.setValue("slug", slug);
    }
  }, [watchTitle, editingCourse, form]);

  const filteredCourses = courses.filter(course =>
    course.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    course.description?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    course.tags.some(tag => tag.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  if (isLoading || !isAuthenticated || user?.role !== "ADMIN") {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="animate-pulse">
          <div className="bg-muted h-8 rounded w-64 mb-4"></div>
          <div className="bg-muted h-32 rounded w-96"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <section className="bg-gradient-to-br from-primary/10 via-accent/5 to-background py-16">
        <div className="container mx-auto px-4">
          <div className="text-center">
            <h1 className="text-4xl font-bold text-foreground mb-4">강의 관리</h1>
            <p className="text-xl text-muted-foreground">
              강의 과정을 생성하고 정렬할 수 있습니다
            </p>
          </div>
        </div>
      </section>

      <div className="container mx-auto px-4 py-12">
        {/* Actions Bar */}
        <Card className="mb-8" data-testid="card-actions">
          <CardContent className="p-6">
            <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
              <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input
                  placeholder="강의 제목, 설명, 태그로 검색..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                  data-testid="input-search"
                />
              </div>

              <Button onClick={openCreateDialog} data-testid="button-create">
                <Plus className="mr-2 w-4 h-4" />
                강의 추가
              </Button>
            </div>
          </CardContent>
        </Card>

        {/* Stats */}
        <div className="grid md:grid-cols-3 gap-6 mb-8">
          <Card data-testid="card-stat-total">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">전체 강의</p>
                  <p className="text-3xl font-bold text-foreground">{courses.length}</p>
                </div>
                <div className="w-12 h-12 bg-blue-100 dark:bg-blue-900 rounded-lg flex items-center justify-center">
                  <BookOpen className="w-6 h-6 text-blue-600 dark:text-blue-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card data-testid="card-stat-filtered">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">검색 결과</p>
                  <p className="text-3xl font-bold text-foreground">{filteredCourses.length}</p>
                </div>
                <div className="w-12 h-12 bg-green-100 dark:bg-green-900 rounded-lg flex items-center justify-center">
                  <Search className="w-6 h-6 text-green-600 dark:text-green-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card data-testid="card-stat-tags">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">사용된 태그</p>
                  <p className="text-3xl font-bold text-foreground">
                    {new Set(courses.flatMap(course => course.tags)).size}
                  </p>
                </div>
                <div className="w-12 h-12 bg-purple-100 dark:bg-purple-900 rounded-lg flex items-center justify-center">
                  <Tag className="w-6 h-6 text-purple-600 dark:text-purple-400" />
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Courses List */}
        <Card data-testid="card-courses-list">
          <CardHeader>
            <CardTitle className="flex items-center">
              <BookOpen className="mr-2 w-5 h-5" />
              강의 목록
            </CardTitle>
          </CardHeader>
          <CardContent>
            {coursesLoading ? (
              <div className="space-y-4">
                {[...Array(5)].map((_, i) => (
                  <div key={i} className="animate-pulse">
                    <div className="flex items-center space-x-4 p-4 rounded-lg border border-border">
                      <div className="bg-muted w-20 h-12 rounded"></div>
                      <div className="flex-1">
                        <div className="bg-muted h-4 rounded w-64 mb-2"></div>
                        <div className="bg-muted h-3 rounded w-32"></div>
                      </div>
                      <div className="bg-muted h-8 rounded w-20"></div>
                    </div>
                  </div>
                ))}
              </div>
            ) : filteredCourses.length === 0 ? (
              <div className="text-center py-12">
                <BookOpen className="w-16 h-16 text-muted-foreground mx-auto mb-4" />
                <h3 className="text-lg font-semibold text-foreground mb-2">
                  {searchTerm ? "검색 결과가 없습니다" : "등록된 강의가 없습니다"}
                </h3>
                <p className="text-muted-foreground mb-4">
                  {searchTerm ? "다른 키워드로 검색해보세요." : "첫 번째 강의를 추가해보세요."}
                </p>
                {!searchTerm && (
                  <Button onClick={openCreateDialog}>
                    <Plus className="mr-2 w-4 h-4" />
                    강의 추가하기
                  </Button>
                )}
              </div>
            ) : (
              <div className="space-y-4">
                {filteredCourses.map((course) => (
                  <div 
                    key={course.id} 
                    className="flex items-center justify-between p-4 rounded-lg border border-border hover:bg-muted/50 transition-colors"
                    data-testid={`course-${course.id}`}
                  >
                    <div className="flex items-center space-x-4 flex-1">
                      <div className="flex items-center cursor-grab">
                        <GripVertical className="w-4 h-4 text-muted-foreground" />
                        <span className="text-sm font-medium text-muted-foreground ml-2 w-8">
                          {course.order}
                        </span>
                      </div>

                      <div className="w-20 h-12 bg-muted rounded flex items-center justify-center overflow-hidden">
                        {course.thumbnail ? (
                          <img 
                            src={course.thumbnail} 
                            alt={course.title}
                            className="w-full h-full object-cover"
                          />
                        ) : (
                          <BookOpen className="w-6 h-6 text-muted-foreground" />
                        )}
                      </div>

                      <div className="flex-1">
                        <h3 className="font-semibold text-foreground">{course.title}</h3>
                        <p className="text-sm text-muted-foreground line-clamp-1">
                          {course.description || "설명이 없습니다"}
                        </p>
                        <div className="flex items-center gap-2 mt-2">
                          <div className="flex flex-wrap gap-1">
                            {course.tags.slice(0, 3).map((tag, index) => (
                              <Badge key={index} variant="outline" className="text-xs">
                                {tag}
                              </Badge>
                            ))}
                            {course.tags.length > 3 && (
                              <Badge variant="outline" className="text-xs">
                                +{course.tags.length - 3}
                              </Badge>
                            )}
                          </div>
                          <span className="text-xs text-muted-foreground flex items-center">
                            <Calendar className="w-3 h-3 mr-1" />
                            {new Date(course.createdAt).toLocaleDateString()}
                          </span>
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center space-x-2">
                      <Button
                        variant="outline"
                        size="sm"
                        asChild
                        data-testid={`button-view-${course.id}`}
                      >
                        <Link href={`/courses/${course.id}`}>
                          <Eye className="w-4 h-4 mr-1" />
                          보기
                        </Link>
                      </Button>
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => openEditDialog(course)}
                        data-testid={`button-edit-${course.id}`}
                      >
                        <Edit className="w-4 h-4 mr-1" />
                        편집
                      </Button>
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => openDeleteDialog(course)}
                        data-testid={`button-delete-${course.id}`}
                      >
                        <Trash2 className="w-4 h-4 mr-1" />
                        삭제
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Create/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={closeDialog}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto" data-testid="dialog-course-form">
          <DialogHeader>
            <DialogTitle className="flex items-center">
              <BookOpen className="mr-2 w-5 h-5" />
              {editingCourse ? "강의 편집" : "새 강의 추가"}
            </DialogTitle>
            <DialogDescription>
              {editingCourse ? "강의 정보를 수정하세요." : "새로운 강의를 등록하세요."}
            </DialogDescription>
          </DialogHeader>

          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="title"
                  render={({ field }) => (
                    <FormItem className="col-span-2">
                      <FormLabel>제목 *</FormLabel>
                      <FormControl>
                        <Input placeholder="강의 제목을 입력하세요" {...field} data-testid="input-title" />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="slug"
                  render={({ field }) => (
                    <FormItem className="col-span-2">
                      <FormLabel>슬러그 *</FormLabel>
                      <FormControl>
                        <Input placeholder="url-friendly-slug" {...field} data-testid="input-slug" />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="description"
                  render={({ field }) => (
                    <FormItem className="col-span-2">
                      <FormLabel>설명</FormLabel>
                      <FormControl>
                        <Textarea 
                          placeholder="강의에 대한 설명을 입력하세요" 
                          rows={4}
                          {...field} 
                          data-testid="textarea-description"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="thumbnail"
                  render={({ field }) => (
                    <FormItem className="col-span-2">
                      <FormLabel>썸네일 URL</FormLabel>
                      <FormControl>
                        <Input 
                          placeholder="https://example.com/thumbnail.jpg" 
                          {...field} 
                          data-testid="input-thumbnail"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="tags"
                  render={({ field }) => (
                    <FormItem className="col-span-2">
                      <FormLabel>태그</FormLabel>
                      <FormControl>
                        <Input 
                          placeholder="토익, 비즈니스, 영어회화 (쉼표로 구분)" 
                          {...field} 
                          data-testid="input-tags"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="order"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>순서</FormLabel>
                      <FormControl>
                        <Input 
                          type="number" 
                          placeholder="0"
                          {...field}
                          onChange={(e) => field.onChange(parseInt(e.target.value) || 0)}
                          data-testid="input-order"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <DialogFooter>
                <Button type="button" variant="outline" onClick={closeDialog} data-testid="button-cancel">
                  <X className="mr-2 w-4 h-4" />
                  취소
                </Button>
                <Button 
                  type="submit" 
                  disabled={createMutation.isPending || updateMutation.isPending}
                  data-testid="button-save"
                >
                  <Save className="mr-2 w-4 h-4" />
                  {createMutation.isPending || updateMutation.isPending 
                    ? "저장 중..." 
                    : editingCourse ? "수정하기" : "생성하기"
                  }
                </Button>
              </DialogFooter>
            </form>
          </Form>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation Dialog */}
      <Dialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <DialogContent data-testid="dialog-delete">
          <DialogHeader>
            <DialogTitle className="flex items-center text-destructive">
              <Trash2 className="mr-2 w-5 h-5" />
              강의 삭제
            </DialogTitle>
            <DialogDescription>
              {deletingCourse && (
                <>
                  <strong>{deletingCourse.title}</strong> 강의를 정말 삭제하시겠습니까?
                  <br />이 강의에 포함된 모든 동영상도 함께 삭제됩니다.
                  <br />이 작업은 되돌릴 수 없습니다.
                </>
              )}
            </DialogDescription>
          </DialogHeader>

          <DialogFooter>
            <Button 
              variant="outline" 
              onClick={() => setDeleteDialogOpen(false)}
              data-testid="button-cancel-delete"
            >
              취소
            </Button>
            <Button
              variant="destructive"
              onClick={() => deletingCourse && deleteMutation.mutate(deletingCourse.id)}
              disabled={deleteMutation.isPending}
              data-testid="button-confirm-delete"
            >
              <Trash2 className="mr-2 w-4 h-4" />
              {deleteMutation.isPending ? "삭제 중..." : "삭제하기"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/pages/admin/members.tsx.content:
import { useAuth } from "@/hooks/useAuth";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { isUnauthorizedError } from "@/lib/authUtils";
import { useState, useEffect } from "react";
import { 
  Users, 
  UserCheck, 
  UserX, 
  Search, 
  Calendar,
  Filter,
  ChevronDown,
  CheckCircle,
  XCircle,
  Clock
} from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/textarea";

interface User {
  id: string;
  email: string;
  firstName?: string;
  lastName?: string;
  profileImageUrl?: string;
  role: "PENDING" | "VERIFIED" | "ADMIN";
  createdAt: string;
  updatedAt: string;
}

export default function AdminMembers() {
  const { user, isAuthenticated, isLoading } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [searchTerm, setSearchTerm] = useState("");
  const [roleFilter, setRoleFilter] = useState<"ALL" | "PENDING" | "VERIFIED" | "ADMIN">("ALL");
  const [selectedUser, setSelectedUser] = useState<User | null>(null);
  const [actionType, setActionType] = useState<"approve" | "reject" | null>(null);
  const [memo, setMemo] = useState("");

  // Redirect if not admin
  useEffect(() => {
    if (!isLoading && (!isAuthenticated || user?.role !== "ADMIN")) {
      toast({
        title: "접근 권한이 없습니다",
        description: "관리자만 접근할 수 있는 페이지입니다.",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/";
      }, 500);
      return;
    }
  }, [isAuthenticated, isLoading, user, toast]);

  const { data: pendingUsers = [], isLoading: usersLoading, error: pendingUsersError } = useQuery<User[]>({
    queryKey: ["/api/admin/users/pending"],
    enabled: isAuthenticated && user?.role === "ADMIN",
  });

  // Handle pendingUsers query errors
  useEffect(() => {
    if (pendingUsersError && isUnauthorizedError(pendingUsersError as Error)) {
      toast({
        title: "인증이 필요합니다",
        description: "다시 로그인해주세요.",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
    }
  }, [pendingUsersError, toast]);

  const approveMutation = useMutation({
    mutationFn: async ({ userId, memo }: { userId: string; memo?: string }) => {
      await apiRequest("POST", `/api/admin/users/${userId}/approve`, { memo });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/users/pending"] });
      toast({
        title: "회원 승인 완료",
        description: "회원이 성공적으로 승인되었습니다.",
      });
      closeDialog();
    },
    onError: (error) => {
      if (isUnauthorizedError(error as Error)) {
        toast({
          title: "인증이 필요합니다",
          description: "다시 로그인해주세요.",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }
      toast({
        title: "승인 실패",
        description: "회원 승인 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  const rejectMutation = useMutation({
    mutationFn: async ({ userId, memo }: { userId: string; memo?: string }) => {
      await apiRequest("POST", `/api/admin/users/${userId}/reject`, { memo });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/users/pending"] });
      toast({
        title: "회원 거절 완료",
        description: "회원 신청이 거절되었습니다.",
      });
      closeDialog();
    },
    onError: (error) => {
      if (isUnauthorizedError(error as Error)) {
        toast({
          title: "인증이 필요합니다",
          description: "다시 로그인해주세요.",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }
      toast({
        title: "거절 실패",
        description: "회원 거절 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  const openApprovalDialog = (user: User, type: "approve" | "reject") => {
    setSelectedUser(user);
    setActionType(type);
    setMemo("");
  };

  const closeDialog = () => {
    setSelectedUser(null);
    setActionType(null);
    setMemo("");
  };

  const handleAction = () => {
    if (!selectedUser || !actionType) return;

    if (actionType === "approve") {
      approveMutation.mutate({ userId: selectedUser.id, memo });
    } else {
      rejectMutation.mutate({ userId: selectedUser.id, memo });
    }
  };

  const filteredUsers = pendingUsers.filter(user => {
    const matchesSearch = 
      user.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (user.firstName?.toLowerCase().includes(searchTerm.toLowerCase())) ||
      (user.lastName?.toLowerCase().includes(searchTerm.toLowerCase()));

    const matchesRole = roleFilter === "ALL" || user.role === roleFilter;

    return matchesSearch && matchesRole;
  });

  const getRoleBadgeColor = (role: string) => {
    switch (role) {
      case "ADMIN":
        return "bg-violet-100 text-violet-800 dark:bg-violet-900 dark:text-violet-200";
      case "VERIFIED":
        return "bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200";
      case "PENDING":
        return "bg-amber-100 text-amber-800 dark:bg-amber-900 dark:text-amber-200";
      default:
        return "bg-gray-100 text-gray-800 dark:bg-gray-900 dark:text-gray-200";
    }
  };

  const getRoleLabel = (role: string) => {
    switch (role) {
      case "ADMIN":
        return "관리자";
      case "VERIFIED":
        return "인증 회원";
      case "PENDING":
        return "승인 대기";
      default:
        return role;
    }
  };

  if (isLoading || !isAuthenticated || user?.role !== "ADMIN") {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="animate-pulse">
          <div className="bg-muted h-8 rounded w-64 mb-4"></div>
          <div className="bg-muted h-32 rounded w-96"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <section className="bg-gradient-to-br from-primary/10 via-accent/5 to-background py-16">
        <div className="container mx-auto px-4">
          <div className="text-center">
            <h1 className="text-4xl font-bold text-foreground mb-4">회원 관리</h1>
            <p className="text-xl text-muted-foreground">
              가입 신청한 회원들을 승인하거나 거절할 수 있습니다
            </p>
          </div>
        </div>
      </section>

      <div className="container mx-auto px-4 py-12">
        {/* Filters and Search */}
        <Card className="mb-8" data-testid="card-filters">
          <CardContent className="p-6">
            <div className="flex flex-col md:flex-row gap-4">
              <div className="flex-1">
                <div className="relative">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                  <Input
                    placeholder="이름 또는 이메일로 검색..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10"
                    data-testid="input-search"
                  />
                </div>
              </div>

              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="outline" data-testid="button-role-filter">
                    <Filter className="mr-2 w-4 h-4" />
                    {roleFilter === "ALL" ? "모든 상태" : getRoleLabel(roleFilter)}
                    <ChevronDown className="ml-2 w-4 h-4" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent>
                  <DropdownMenuItem onClick={() => setRoleFilter("ALL")}>
                    모든 상태
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setRoleFilter("PENDING")}>
                    승인 대기
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setRoleFilter("VERIFIED")}>
                    인증 회원
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setRoleFilter("ADMIN")}>
                    관리자
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </CardContent>
        </Card>

        {/* Stats */}
        <div className="grid md:grid-cols-3 gap-6 mb-8">
          <Card data-testid="card-stat-total">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">전체 대기</p>
                  <p className="text-3xl font-bold text-foreground">{pendingUsers.length}</p>
                </div>
                <div className="w-12 h-12 bg-amber-100 dark:bg-amber-900 rounded-lg flex items-center justify-center">
                  <Clock className="w-6 h-6 text-amber-600 dark:text-amber-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card data-testid="card-stat-filtered">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">검색 결과</p>
                  <p className="text-3xl font-bold text-foreground">{filteredUsers.length}</p>
                </div>
                <div className="w-12 h-12 bg-blue-100 dark:bg-blue-900 rounded-lg flex items-center justify-center">
                  <Search className="w-6 h-6 text-blue-600 dark:text-blue-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card data-testid="card-stat-processing">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">처리 중</p>
                  <p className="text-3xl font-bold text-foreground">
                    {approveMutation.isPending || rejectMutation.isPending ? 1 : 0}
                  </p>
                </div>
                <div className="w-12 h-12 bg-green-100 dark:bg-green-900 rounded-lg flex items-center justify-center">
                  <Users className="w-6 h-6 text-green-600 dark:text-green-400" />
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Members List */}
        <Card data-testid="card-members-list">
          <CardHeader>
            <CardTitle className="flex items-center">
              <Users className="mr-2 w-5 h-5" />
              회원 목록
            </CardTitle>
          </CardHeader>
          <CardContent>
            {usersLoading ? (
              <div className="space-y-4">
                {[...Array(5)].map((_, i) => (
                  <div key={i} className="animate-pulse">
                    <div className="flex items-center space-x-4 p-4 rounded-lg border border-border">
                      <div className="bg-muted w-12 h-12 rounded-full"></div>
                      <div className="flex-1">
                        <div className="bg-muted h-4 rounded w-48 mb-2"></div>
                        <div className="bg-muted h-3 rounded w-32"></div>
                      </div>
                      <div className="bg-muted h-8 rounded w-20"></div>
                      <div className="bg-muted h-8 rounded w-16"></div>
                    </div>
                  </div>
                ))}
              </div>
            ) : filteredUsers.length === 0 ? (
              <div className="text-center py-12">
                <Users className="w-16 h-16 text-muted-foreground mx-auto mb-4" />
                <h3 className="text-lg font-semibold text-foreground mb-2">
                  {searchTerm || roleFilter !== "ALL" ? "검색 결과가 없습니다" : "승인 대기 중인 회원이 없습니다"}
                </h3>
                <p className="text-muted-foreground">
                  {searchTerm || roleFilter !== "ALL" ? "다른 조건으로 검색해보세요." : "새로운 가입 신청을 기다리고 있습니다."}
                </p>
              </div>
            ) : (
              <div className="space-y-4">
                {filteredUsers.map((pendingUser) => (
                  <div 
                    key={pendingUser.id} 
                    className="flex items-center justify-between p-4 rounded-lg border border-border hover:bg-muted/50 transition-colors"
                    data-testid={`member-${pendingUser.id}`}
                  >
                    <div className="flex items-center space-x-4">
                      <Avatar className="w-12 h-12">
                        <AvatarImage src={pendingUser.profileImageUrl || undefined} />
                        <AvatarFallback>
                          {pendingUser.firstName?.[0] || pendingUser.email[0]}
                        </AvatarFallback>
                      </Avatar>
                      <div>
                        <h3 className="font-semibold text-foreground">
                          {pendingUser.firstName || pendingUser.email}
                        </h3>
                        <p className="text-sm text-muted-foreground">
                          {pendingUser.email}
                        </p>
                        <div className="flex items-center gap-2 mt-1">
                          <Badge className={getRoleBadgeColor(pendingUser.role)} variant="secondary">
                            {getRoleLabel(pendingUser.role)}
                          </Badge>
                          <span className="text-xs text-muted-foreground flex items-center">
                            <Calendar className="w-3 h-3 mr-1" />
                            {new Date(pendingUser.createdAt).toLocaleDateString()}
                          </span>
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center space-x-2">
                      {pendingUser.role === "PENDING" && (
                        <>
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => openApprovalDialog(pendingUser, "approve")}
                            disabled={approveMutation.isPending || rejectMutation.isPending}
                            data-testid={`button-approve-${pendingUser.id}`}
                          >
                            <UserCheck className="w-4 h-4 mr-1" />
                            승인
                          </Button>
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => openApprovalDialog(pendingUser, "reject")}
                            disabled={approveMutation.isPending || rejectMutation.isPending}
                            data-testid={`button-reject-${pendingUser.id}`}
                          >
                            <UserX className="w-4 h-4 mr-1" />
                            거절
                          </Button>
                        </>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Approval/Rejection Dialog */}
      <Dialog open={!!selectedUser && !!actionType} onOpenChange={closeDialog}>
        <DialogContent data-testid="dialog-action">
          <DialogHeader>
            <DialogTitle className="flex items-center">
              {actionType === "approve" ? (
                <CheckCircle className="mr-2 w-5 h-5 text-green-600" />
              ) : (
                <XCircle className="mr-2 w-5 h-5 text-red-600" />
              )}
              회원 {actionType === "approve" ? "승인" : "거절"}
            </DialogTitle>
            <DialogDescription>
              {selectedUser && (
                <>
                  <strong>{selectedUser.firstName || selectedUser.email}</strong>님의 가입 신청을{" "}
                  {actionType === "approve" ? "승인" : "거절"}하시겠습니까?
                </>
              )}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium text-foreground">
                메모 (선택사항)
              </label>
              <Textarea
                placeholder={`${actionType === "approve" ? "승인" : "거절"} 사유나 메모를 입력하세요...`}
                value={memo}
                onChange={(e) => setMemo(e.target.value)}
                rows={3}
                data-testid="textarea-memo"
              />
            </div>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={closeDialog} data-testid="button-cancel">
              취소
            </Button>
            <Button
              onClick={handleAction}
              disabled={approveMutation.isPending || rejectMutation.isPending}
              variant={actionType === "approve" ? "default" : "destructive"}
              data-testid="button-confirm"
            >
              {approveMutation.isPending || rejectMutation.isPending ? (
                "처리 중..."
              ) : (
                actionType === "approve" ? "승인하기" : "거절하기"
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/pages/admin/notices.tsx.content:
import { useAuth } from "@/hooks/useAuth";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { isUnauthorizedError } from "@/lib/authUtils";
import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { 
  Calendar, 
  Plus, 
  Edit, 
  Trash2, 
  Search, 
  Clock,
  Eye,
  EyeOff,
  Save,
  X,
  MessageSquare,
  Filter
} from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";

interface Notice {
  id: string;
  title: string;
  body: string;
  startsAt?: string;
  endsAt?: string;
  createdAt: string;
}

const noticeFormSchema = z.object({
  title: z.string().min(1, "제목을 입력해주세요"),
  body: z.string().min(1, "내용을 입력해주세요"),
  startsAt: z.string().optional(),
  endsAt: z.string().optional(),
});

type NoticeFormData = z.infer<typeof noticeFormSchema>;

export default function AdminNotices() {
  const { user, isAuthenticated, isLoading } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState<"ALL" | "ACTIVE" | "UPCOMING" | "EXPIRED">("ALL");
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingNotice, setEditingNotice] = useState<Notice | null>(null);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [deletingNotice, setDeletingNotice] = useState<Notice | null>(null);

  const form = useForm<NoticeFormData>({
    resolver: zodResolver(noticeFormSchema),
    defaultValues: {
      title: "",
      body: "",
      startsAt: "",
      endsAt: "",
    },
  });

  // Redirect if not admin
  useEffect(() => {
    if (!isLoading && (!isAuthenticated || user?.role !== "ADMIN")) {
      toast({
        title: "접근 권한이 없습니다",
        description: "관리자만 접근할 수 있는 페이지입니다.",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/";
      }, 500);
      return;
    }
  }, [isAuthenticated, isLoading, user, toast]);

  const { data: notices = [], isLoading: noticesLoading, error: noticesError } = useQuery<Notice[]>({
    queryKey: ["/api/admin/notices"],
    enabled: isAuthenticated && user?.role === "ADMIN",
  });

  // Handle notices query errors
  useEffect(() => {
    if (noticesError && isUnauthorizedError(noticesError as Error)) {
      toast({
        title: "인증이 필요합니다",
        description: "다시 로그인해주세요.",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
    }
  }, [noticesError, toast]);

  const createMutation = useMutation({
    mutationFn: async (data: NoticeFormData) => {
      const payload = {
        ...data,
        startsAt: data.startsAt ? new Date(data.startsAt).toISOString() : undefined,
        endsAt: data.endsAt ? new Date(data.endsAt).toISOString() : undefined,
      };
      await apiRequest("POST", "/api/admin/notices", payload);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/notices"] });
      toast({
        title: "공지사항 생성 완료",
        description: "새로운 공지사항이 성공적으로 생성되었습니다.",
      });
      closeDialog();
    },
    onError: (error) => {
      toast({
        title: "생성 실패",
        description: "공지사항 생성 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  const updateMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: NoticeFormData }) => {
      const payload = {
        ...data,
        startsAt: data.startsAt ? new Date(data.startsAt).toISOString() : undefined,
        endsAt: data.endsAt ? new Date(data.endsAt).toISOString() : undefined,
      };
      await apiRequest("PUT", `/api/admin/notices/${id}`, payload);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/notices"] });
      toast({
        title: "공지사항 수정 완료",
        description: "공지사항이 성공적으로 수정되었습니다.",
      });
      closeDialog();
    },
    onError: (error) => {
      toast({
        title: "수정 실패",
        description: "공지사항 수정 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      await apiRequest("DELETE", `/api/admin/notices/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/notices"] });
      toast({
        title: "공지사항 삭제 완료",
        description: "공지사항이 성공적으로 삭제되었습니다.",
      });
      setDeleteDialogOpen(false);
      setDeletingNotice(null);
    },
    onError: (error) => {
      toast({
        title: "삭제 실패",
        description: "공지사항 삭제 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  const openCreateDialog = () => {
    setEditingNotice(null);
    form.reset();
    setDialogOpen(true);
  };

  const openEditDialog = (notice: Notice) => {
    setEditingNotice(notice);
    form.reset({
      title: notice.title,
      body: notice.body,
      startsAt: notice.startsAt ? new Date(notice.startsAt).toISOString().slice(0, 16) : "",
      endsAt: notice.endsAt ? new Date(notice.endsAt).toISOString().slice(0, 16) : "",
    });
    setDialogOpen(true);
  };

  const closeDialog = () => {
    setDialogOpen(false);
    setEditingNotice(null);
    form.reset();
  };

  const openDeleteDialog = (notice: Notice) => {
    setDeletingNotice(notice);
    setDeleteDialogOpen(true);
  };

  const onSubmit = (data: NoticeFormData) => {
    if (editingNotice) {
      updateMutation.mutate({ id: editingNotice.id, data });
    } else {
      createMutation.mutate(data);
    }
  };

  const getNoticeStatus = (notice: Notice) => {
    const now = new Date();
    const start = notice.startsAt ? new Date(notice.startsAt) : null;
    const end = notice.endsAt ? new Date(notice.endsAt) : null;

    if (start && now < start) {
      return {
        status: "upcoming",
        label: `공개 예정 ${start.toLocaleDateString()}`,
        color: "bg-amber-100 text-amber-800 dark:bg-amber-900 dark:text-amber-200",
        icon: <Clock className="w-3 h-3 mr-1" />,
      };
    }

    if (end && now > end) {
      return {
        status: "expired",
        label: "게시 기간 만료",
        color: "bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200",
        icon: <EyeOff className="w-3 h-3 mr-1" />,
      };
    }

    if (start && end) {
      return {
        status: "active",
        label: `게시 중 ~${end.toLocaleDateString()}`,
        color: "bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200",
        icon: <Eye className="w-3 h-3 mr-1" />,
      };
    }

    return {
      status: "active",
      label: "게시 중",
      color: "bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200",
      icon: <Eye className="w-3 h-3 mr-1" />,
    };
  };

  const filteredNotices = notices.filter(notice => {
    const matchesSearch = 
      notice.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      notice.body.toLowerCase().includes(searchTerm.toLowerCase());

    if (!matchesSearch) return false;

    const status = getNoticeStatus(notice).status;
    if (statusFilter === "ALL") return true;
    return statusFilter.toLowerCase() === status;
  });

  const getStatusCounts = () => {
    const counts = { active: 0, upcoming: 0, expired: 0 };
    notices.forEach(notice => {
      const status = getNoticeStatus(notice).status;
      counts[status as keyof typeof counts]++;
    });
    return counts;
  };

  const statusCounts = getStatusCounts();

  if (isLoading || !isAuthenticated || user?.role !== "ADMIN") {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="animate-pulse">
          <div className="bg-muted h-8 rounded w-64 mb-4"></div>
          <div className="bg-muted h-32 rounded w-96"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <section className="bg-gradient-to-br from-primary/10 via-accent/5 to-background py-16">
        <div className="container mx-auto px-4">
          <div className="text-center">
            <h1 className="text-4xl font-bold text-foreground mb-4">공지사항 관리</h1>
            <p className="text-xl text-muted-foreground">
              홈페이지에 표시될 공지사항을 작성하고 게시 기간을 설정할 수 있습니다
            </p>
          </div>
        </div>
      </section>

      <div className="container mx-auto px-4 py-12">
        {/* Actions Bar */}
        <Card className="mb-8" data-testid="card-actions">
          <CardContent className="p-6">
            <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
              <div className="flex flex-col md:flex-row gap-4 flex-1">
                <div className="relative flex-1">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                  <Input
                    placeholder="제목 또는 내용으로 검색..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10"
                    data-testid="input-search"
                  />
                </div>

                <Select value={statusFilter} onValueChange={setStatusFilter}>
                  <SelectTrigger className="w-full md:w-48" data-testid="select-status-filter">
                    <SelectValue placeholder="상태" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="ALL">모든 상태</SelectItem>
                    <SelectItem value="ACTIVE">게시 중</SelectItem>
                    <SelectItem value="UPCOMING">게시 예정</SelectItem>
                    <SelectItem value="EXPIRED">게시 만료</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <Button onClick={openCreateDialog} data-testid="button-create">
                <Plus className="mr-2 w-4 h-4" />
                공지사항 추가
              </Button>
            </div>
          </CardContent>
        </Card>

        {/* Stats */}
        <div className="grid md:grid-cols-4 gap-6 mb-8">
          <Card data-testid="card-stat-total">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">전체 공지</p>
                  <p className="text-3xl font-bold text-foreground">{notices.length}</p>
                </div>
                <div className="w-12 h-12 bg-blue-100 dark:bg-blue-900 rounded-lg flex items-center justify-center">
                  <MessageSquare className="w-6 h-6 text-blue-600 dark:text-blue-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card data-testid="card-stat-active">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">게시 중</p>
                  <p className="text-3xl font-bold text-foreground">{statusCounts.active}</p>
                </div>
                <div className="w-12 h-12 bg-green-100 dark:bg-green-900 rounded-lg flex items-center justify-center">
                  <Eye className="w-6 h-6 text-green-600 dark:text-green-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card data-testid="card-stat-upcoming">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">게시 예정</p>
                  <p className="text-3xl font-bold text-foreground">{statusCounts.upcoming}</p>
                </div>
                <div className="w-12 h-12 bg-amber-100 dark:bg-amber-900 rounded-lg flex items-center justify-center">
                  <Clock className="w-6 h-6 text-amber-600 dark:text-amber-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card data-testid="card-stat-expired">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">게시 만료</p>
                  <p className="text-3xl font-bold text-foreground">{statusCounts.expired}</p>
                </div>
                <div className="w-12 h-12 bg-red-100 dark:bg-red-900 rounded-lg flex items-center justify-center">
                  <EyeOff className="w-6 h-6 text-red-600 dark:text-red-400" />
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Notices List */}
        <Card data-testid="card-notices-list">
          <CardHeader>
            <CardTitle className="flex items-center">
              <MessageSquare className="mr-2 w-5 h-5" />
              공지사항 목록
            </CardTitle>
          </CardHeader>
          <CardContent>
            {noticesLoading ? (
              <div className="space-y-4">
                {[...Array(5)].map((_, i) => (
                  <div key={i} className="animate-pulse">
                    <div className="flex items-start space-x-4 p-4 rounded-lg border border-border">
                      <div className="flex-1">
                        <div className="bg-muted h-4 rounded w-64 mb-2"></div>
                        <div className="bg-muted h-3 rounded w-32 mb-2"></div>
                        <div className="bg-muted h-3 rounded w-96"></div>
                      </div>
                      <div className="bg-muted h-8 rounded w-20"></div>
                    </div>
                  </div>
                ))}
              </div>
            ) : filteredNotices.length === 0 ? (
              <div className="text-center py-12">
                <MessageSquare className="w-16 h-16 text-muted-foreground mx-auto mb-4" />
                <h3 className="text-lg font-semibold text-foreground mb-2">
                  {searchTerm || statusFilter !== "ALL" 
                    ? "검색 결과가 없습니다" 
                    : "등록된 공지사항이 없습니다"
                  }
                </h3>
                <p className="text-muted-foreground mb-4">
                  {searchTerm || statusFilter !== "ALL"
                    ? "다른 조건으로 검색해보세요."
                    : "첫 번째 공지사항을 추가해보세요."
                  }
                </p>
                {(!searchTerm && statusFilter === "ALL") && (
                  <Button onClick={openCreateDialog}>
                    <Plus className="mr-2 w-4 h-4" />
                    공지사항 추가하기
                  </Button>
                )}
              </div>
            ) : (
              <div className="space-y-4">
                {filteredNotices.map((notice) => {
                  const status = getNoticeStatus(notice);

                  return (
                    <div 
                      key={notice.id} 
                      className="flex items-start justify-between p-4 rounded-lg border border-border hover:bg-muted/50 transition-colors"
                      data-testid={`notice-${notice.id}`}
                    >
                      <div className="flex-1">
                        <div className="flex items-start justify-between mb-2">
                          <h3 className="font-semibold text-foreground">{notice.title}</h3>
                          <Badge className={`${status.color} flex items-center ml-4`} variant="secondary">
                            {status.icon}
                            {status.label}
                          </Badge>
                        </div>

                        <p className="text-muted-foreground text-sm mb-3 line-clamp-2">
                          {notice.body}
                        </p>

                        <div className="flex items-center gap-4 text-xs text-muted-foreground">
                          <span className="flex items-center">
                            <Calendar className="w-3 h-3 mr-1" />
                            작성: {new Date(notice.createdAt).toLocaleString()}
                          </span>
                          {notice.startsAt && (
                            <span className="flex items-center">
                              <Eye className="w-3 h-3 mr-1" />
                              시작: {new Date(notice.startsAt).toLocaleString()}
                            </span>
                          )}
                          {notice.endsAt && (
                            <span className="flex items-center">
                              <EyeOff className="w-3 h-3 mr-1" />
                              종료: {new Date(notice.endsAt).toLocaleString()}
                            </span>
                          )}
                        </div>
                      </div>

                      <div className="flex items-center space-x-2 ml-4">
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => openEditDialog(notice)}
                          data-testid={`button-edit-${notice.id}`}
                        >
                          <Edit className="w-4 h-4 mr-1" />
                          편집
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => openDeleteDialog(notice)}
                          data-testid={`button-delete-${notice.id}`}
                        >
                          <Trash2 className="w-4 h-4 mr-1" />
                          삭제
                        </Button>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Create/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={closeDialog}>
        <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto" data-testid="dialog-notice-form">
          <DialogHeader>
            <DialogTitle className="flex items-center">
              <MessageSquare className="mr-2 w-5 h-5" />
              {editingNotice ? "공지사항 편집" : "새 공지사항 추가"}
            </DialogTitle>
            <DialogDescription>
              {editingNotice ? "공지사항 정보를 수정하세요." : "새로운 공지사항을 작성하세요."}
            </DialogDescription>
          </DialogHeader>

          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
              <FormField
                control={form.control}
                name="title"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>제목 *</FormLabel>
                    <FormControl>
                      <Input placeholder="공지사항 제목을 입력하세요" {...field} data-testid="input-title" />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="body"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>내용 *</FormLabel>
                    <FormControl>
                      <Textarea 
                        placeholder="공지사항 내용을 입력하세요" 
                        rows={8}
                        {...field} 
                        data-testid="textarea-body"
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <div className="grid grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="startsAt"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>게시 시작 시간</FormLabel>
                      <FormControl>
                        <Input 
                          type="datetime-local" 
                          {...field} 
                          data-testid="input-starts-at"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="endsAt"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>게시 종료 시간</FormLabel>
                      <FormControl>
                        <Input 
                          type="datetime-local" 
                          {...field} 
                          data-testid="input-ends-at"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <div className="bg-muted/50 p-4 rounded-lg">
                <h4 className="font-medium text-foreground mb-2">게시 기간 안내</h4>
                <ul className="text-sm text-muted-foreground space-y-1">
                  <li>• 게시 시작/종료 시간을 모두 비워두면 즉시 게시되어 계속 표시됩니다</li>
                  <li>• 시작 시간만 설정하면 해당 시간부터 계속 표시됩니다</li>
                  <li>• 종료 시간만 설정하면 즉시 게시되어 해당 시간까지 표시됩니다</li>
                  <li>• 시작/종료 시간을 모두 설정하면 해당 기간 동안만 표시됩니다</li>
                </ul>
              </div>

              <DialogFooter>
                <Button type="button" variant="outline" onClick={closeDialog} data-testid="button-cancel">
                  <X className="mr-2 w-4 h-4" />
                  취소
                </Button>
                <Button 
                  type="submit" 
                  disabled={createMutation.isPending || updateMutation.isPending}
                  data-testid="button-save"
                >
                  <Save className="mr-2 w-4 h-4" />
                  {createMutation.isPending || updateMutation.isPending 
                    ? "저장 중..." 
                    : editingNotice ? "수정하기" : "게시하기"
                  }
                </Button>
              </DialogFooter>
            </form>
          </Form>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation Dialog */}
      <Dialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <DialogContent data-testid="dialog-delete">
          <DialogHeader>
            <DialogTitle className="flex items-center text-destructive">
              <Trash2 className="mr-2 w-5 h-5" />
              공지사항 삭제
            </DialogTitle>
            <DialogDescription>
              {deletingNotice && (
                <>
                  <strong>{deletingNotice.title}</strong> 공지사항을 정말 삭제하시겠습니까?
                  <br />이 작업은 되돌릴 수 없습니다.
                </>
              )}
            </DialogDescription>
          </DialogHeader>

          <DialogFooter>
            <Button 
              variant="outline" 
              onClick={() => setDeleteDialogOpen(false)}
              data-testid="button-cancel-delete"
            >
              취소
            </Button>
            <Button
              variant="destructive"
              onClick={() => deletingNotice && deleteMutation.mutate(deletingNotice.id)}
              disabled={deleteMutation.isPending}
              data-testid="button-confirm-delete"
            >
              <Trash2 className="mr-2 w-4 h-4" />
              {deleteMutation.isPending ? "삭제 중..." : "삭제하기"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/pages/admin/videos.tsx.content:
import { useAuth } from "@/hooks/useAuth";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { isUnauthorizedError } from "@/lib/authUtils";
import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { 
  Video, 
  Plus, 
  Edit, 
  Trash2, 
  Search, 
  Filter,
  Calendar,
  Clock,
  Eye,
  EyeOff,
  Link as LinkIcon,
  Save,
  X
} from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Switch } from "@/components/ui/switch";

interface Course {
  id: string;
  title: string;
  slug: string;
}

interface VideoData {
  id: string;
  courseId: string;
  title: string;
  description?: string;
  externalUrl: string;
  durationSec?: number;
  isPublished: boolean;
  accessStart?: string;
  accessEnd?: string;
  createdAt: string;
  updatedAt: string;
  course?: Course;
}

const videoFormSchema = z.object({
  courseId: z.string().min(1, "강의 과정을 선택해주세요"),
  title: z.string().min(1, "제목을 입력해주세요"),
  description: z.string().optional(),
  externalUrl: z.string().url("올바른 URL을 입력해주세요"),
  durationSec: z.number().optional(),
  isPublished: z.boolean(),
  accessStart: z.string().optional(),
  accessEnd: z.string().optional(),
});

type VideoFormData = z.infer<typeof videoFormSchema>;

export default function AdminVideos() {
  const { user, isAuthenticated, isLoading } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [searchTerm, setSearchTerm] = useState("");
  const [courseFilter, setCourseFilter] = useState<string>("ALL");
  const [publishedFilter, setPublishedFilter] = useState<"ALL" | "PUBLISHED" | "UNPUBLISHED">("ALL");
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingVideo, setEditingVideo] = useState<VideoData | null>(null);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [deletingVideo, setDeletingVideo] = useState<VideoData | null>(null);

  const form = useForm<VideoFormData>({
    resolver: zodResolver(videoFormSchema),
    defaultValues: {
      courseId: "",
      title: "",
      description: "",
      externalUrl: "",
      durationSec: undefined,
      isPublished: true,
      accessStart: "",
      accessEnd: "",
    },
  });

  // Redirect if not admin
  useEffect(() => {
    if (!isLoading && (!isAuthenticated || user?.role !== "ADMIN")) {
      toast({
        title: "접근 권한이 없습니다",
        description: "관리자만 접근할 수 있는 페이지입니다.",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/";
      }, 500);
      return;
    }
  }, [isAuthenticated, isLoading, user, toast]);

  const { data: courses = [] } = useQuery<Course[]>({
    queryKey: ["/api/admin/courses"],
    enabled: isAuthenticated && user?.role === "ADMIN",
  });

  const { data: videos = [], isLoading: videosLoading, error: videosError } = useQuery<VideoData[]>({
    queryKey: ["/api/admin/videos"],
    enabled: isAuthenticated && user?.role === "ADMIN",
  });

  // Handle videos query errors
  useEffect(() => {
    if (videosError && isUnauthorizedError(videosError as Error)) {
      toast({
        title: "인증이 필요합니다",
        description: "다시 로그인해주세요.",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
    }
  }, [videosError, toast]);

  const createMutation = useMutation({
    mutationFn: async (data: VideoFormData) => {
      const payload = {
        ...data,
        accessStart: data.accessStart ? new Date(data.accessStart).toISOString() : undefined,
        accessEnd: data.accessEnd ? new Date(data.accessEnd).toISOString() : undefined,
      };
      await apiRequest("POST", "/api/admin/videos", payload);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/videos"] });
      toast({
        title: "동영상 생성 완료",
        description: "새로운 동영상이 성공적으로 생성되었습니다.",
      });
      closeDialog();
    },
    onError: (error) => {
      toast({
        title: "생성 실패",
        description: "동영상 생성 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  const updateMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: Partial<VideoFormData> }) => {
      const payload = {
        ...data,
        accessStart: data.accessStart ? new Date(data.accessStart).toISOString() : undefined,
        accessEnd: data.accessEnd ? new Date(data.accessEnd).toISOString() : undefined,
      };
      await apiRequest("PUT", `/api/admin/videos/${id}`, payload);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/videos"] });
      toast({
        title: "동영상 수정 완료",
        description: "동영상이 성공적으로 수정되었습니다.",
      });
      closeDialog();
    },
    onError: (error) => {
      toast({
        title: "수정 실패",
        description: "동영상 수정 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      await apiRequest("DELETE", `/api/admin/videos/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/videos"] });
      toast({
        title: "동영상 삭제 완료",
        description: "동영상이 성공적으로 삭제되었습니다.",
      });
      setDeleteDialogOpen(false);
      setDeletingVideo(null);
    },
    onError: (error) => {
      toast({
        title: "삭제 실패",
        description: "동영상 삭제 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  const openCreateDialog = () => {
    setEditingVideo(null);
    form.reset();
    setDialogOpen(true);
  };

  const openEditDialog = (video: VideoData) => {
    setEditingVideo(video);
    form.reset({
      courseId: video.courseId,
      title: video.title,
      description: video.description || "",
      externalUrl: video.externalUrl,
      durationSec: video.durationSec || undefined,
      isPublished: video.isPublished,
      accessStart: video.accessStart ? new Date(video.accessStart).toISOString().slice(0, 16) : "",
      accessEnd: video.accessEnd ? new Date(video.accessEnd).toISOString().slice(0, 16) : "",
    });
    setDialogOpen(true);
  };

  const closeDialog = () => {
    setDialogOpen(false);
    setEditingVideo(null);
    form.reset();
  };

  const openDeleteDialog = (video: VideoData) => {
    setDeletingVideo(video);
    setDeleteDialogOpen(true);
  };

  const onSubmit = (data: VideoFormData) => {
    if (editingVideo) {
      updateMutation.mutate({ id: editingVideo.id, data });
    } else {
      createMutation.mutate(data);
    }
  };

  const formatDuration = (seconds?: number) => {
    if (!seconds) return "미정";
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    const secs = seconds % 60;

    if (hours > 0) {
      return `${hours}:${minutes.toString().padStart(2, "0")}:${secs.toString().padStart(2, "0")}`;
    }
    return `${minutes}:${secs.toString().padStart(2, "0")}`;
  };

  const getAccessStatus = (video: VideoData) => {
    const now = new Date();
    const start = video.accessStart ? new Date(video.accessStart) : null;
    const end = video.accessEnd ? new Date(video.accessEnd) : null;

    if (!video.isPublished) {
      return {
        status: "unpublished",
        label: "비공개",
        color: "bg-gray-100 text-gray-800 dark:bg-gray-900 dark:text-gray-200",
      };
    }

    if (start && now < start) {
      return {
        status: "upcoming",
        label: `공개 예정 ${start.toLocaleDateString()}`,
        color: "bg-amber-100 text-amber-800 dark:bg-amber-900 dark:text-amber-200",
      };
    }

    if (end && now > end) {
      return {
        status: "expired",
        label: "시청 기간 만료",
        color: "bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200",
      };
    }

    if (start && end) {
      return {
        status: "active",
        label: `OPEN ~${end.toLocaleDateString()}`,
        color: "bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200",
      };
    }

    return {
      status: "open",
      label: "시청 가능",
      color: "bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200",
    };
  };

  const filteredVideos = videos.filter(video => {
    const matchesSearch = 
      video.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (video.description?.toLowerCase().includes(searchTerm.toLowerCase()));

    const matchesCourse = courseFilter === "ALL" || video.courseId === courseFilter;

    const matchesPublished = 
      publishedFilter === "ALL" || 
      (publishedFilter === "PUBLISHED" && video.isPublished) ||
      (publishedFilter === "UNPUBLISHED" && !video.isPublished);

    return matchesSearch && matchesCourse && matchesPublished;
  });

  if (isLoading || !isAuthenticated || user?.role !== "ADMIN") {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="animate-pulse">
          <div className="bg-muted h-8 rounded w-64 mb-4"></div>
          <div className="bg-muted h-32 rounded w-96"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <section className="bg-gradient-to-br from-primary/10 via-accent/5 to-background py-16">
        <div className="container mx-auto px-4">
          <div className="text-center">
            <h1 className="text-4xl font-bold text-foreground mb-4">동영상 관리</h1>
            <p className="text-xl text-muted-foreground">
              강의 동영상을 등록하고 접근 기간을 설정할 수 있습니다
            </p>
          </div>
        </div>
      </section>

      <div className="container mx-auto px-4 py-12">
        {/* Actions Bar */}
        <Card className="mb-8" data-testid="card-actions">
          <CardContent className="p-6">
            <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
              <div className="flex flex-col md:flex-row gap-4 flex-1">
                <div className="relative flex-1">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                  <Input
                    placeholder="동영상 제목으로 검색..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10"
                    data-testid="input-search"
                  />
                </div>

                <Select value={courseFilter} onValueChange={setCourseFilter}>
                  <SelectTrigger className="w-full md:w-48" data-testid="select-course-filter">
                    <SelectValue placeholder="강의 과정" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="ALL">모든 과정</SelectItem>
                    {courses.map((course) => (
                      <SelectItem key={course.id} value={course.id}>
                        {course.title}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>

                <Select value={publishedFilter} onValueChange={setPublishedFilter}>
                  <SelectTrigger className="w-full md:w-32" data-testid="select-published-filter">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="ALL">전체</SelectItem>
                    <SelectItem value="PUBLISHED">공개</SelectItem>
                    <SelectItem value="UNPUBLISHED">비공개</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <Button onClick={openCreateDialog} data-testid="button-create">
                <Plus className="mr-2 w-4 h-4" />
                동영상 추가
              </Button>
            </div>
          </CardContent>
        </Card>

        {/* Stats */}
        <div className="grid md:grid-cols-4 gap-6 mb-8">
          <Card data-testid="card-stat-total">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">전체 동영상</p>
                  <p className="text-3xl font-bold text-foreground">{videos.length}</p>
                </div>
                <div className="w-12 h-12 bg-blue-100 dark:bg-blue-900 rounded-lg flex items-center justify-center">
                  <Video className="w-6 h-6 text-blue-600 dark:text-blue-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card data-testid="card-stat-published">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">공개 동영상</p>
                  <p className="text-3xl font-bold text-foreground">
                    {videos.filter(v => v.isPublished).length}
                  </p>
                </div>
                <div className="w-12 h-12 bg-green-100 dark:bg-green-900 rounded-lg flex items-center justify-center">
                  <Eye className="w-6 h-6 text-green-600 dark:text-green-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card data-testid="card-stat-unpublished">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">비공개 동영상</p>
                  <p className="text-3xl font-bold text-foreground">
                    {videos.filter(v => !v.isPublished).length}
                  </p>
                </div>
                <div className="w-12 h-12 bg-gray-100 dark:bg-gray-900 rounded-lg flex items-center justify-center">
                  <EyeOff className="w-6 h-6 text-gray-600 dark:text-gray-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card data-testid="card-stat-filtered">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">검색 결과</p>
                  <p className="text-3xl font-bold text-foreground">{filteredVideos.length}</p>
                </div>
                <div className="w-12 h-12 bg-purple-100 dark:bg-purple-900 rounded-lg flex items-center justify-center">
                  <Search className="w-6 h-6 text-purple-600 dark:text-purple-400" />
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Videos List */}
        <Card data-testid="card-videos-list">
          <CardHeader>
            <CardTitle className="flex items-center">
              <Video className="mr-2 w-5 h-5" />
              동영상 목록
            </CardTitle>
          </CardHeader>
          <CardContent>
            {videosLoading ? (
              <div className="space-y-4">
                {[...Array(5)].map((_, i) => (
                  <div key={i} className="animate-pulse">
                    <div className="flex items-center space-x-4 p-4 rounded-lg border border-border">
                      <div className="bg-muted w-20 h-12 rounded"></div>
                      <div className="flex-1">
                        <div className="bg-muted h-4 rounded w-64 mb-2"></div>
                        <div className="bg-muted h-3 rounded w-32"></div>
                      </div>
                      <div className="bg-muted h-8 rounded w-20"></div>
                    </div>
                  </div>
                ))}
              </div>
            ) : filteredVideos.length === 0 ? (
              <div className="text-center py-12">
                <Video className="w-16 h-16 text-muted-foreground mx-auto mb-4" />
                <h3 className="text-lg font-semibold text-foreground mb-2">
                  {searchTerm || courseFilter !== "ALL" || publishedFilter !== "ALL" 
                    ? "검색 결과가 없습니다" 
                    : "등록된 동영상이 없습니다"
                  }
                </h3>
                <p className="text-muted-foreground mb-4">
                  {searchTerm || courseFilter !== "ALL" || publishedFilter !== "ALL"
                    ? "다른 조건으로 검색해보세요."
                    : "첫 번째 동영상을 추가해보세요."
                  }
                </p>
                {(!searchTerm && courseFilter === "ALL" && publishedFilter === "ALL") && (
                  <Button onClick={openCreateDialog}>
                    <Plus className="mr-2 w-4 h-4" />
                    동영상 추가하기
                  </Button>
                )}
              </div>
            ) : (
              <div className="space-y-4">
                {filteredVideos.map((video) => {
                  const accessStatus = getAccessStatus(video);
                  const course = courses.find(c => c.id === video.courseId);

                  return (
                    <div 
                      key={video.id} 
                      className="flex items-center justify-between p-4 rounded-lg border border-border hover:bg-muted/50 transition-colors"
                      data-testid={`video-${video.id}`}
                    >
                      <div className="flex items-center space-x-4 flex-1">
                        <div className="w-20 h-12 bg-muted rounded flex items-center justify-center">
                          <Video className="w-6 h-6 text-muted-foreground" />
                        </div>
                        <div className="flex-1">
                          <h3 className="font-semibold text-foreground">{video.title}</h3>
                          <div className="flex items-center gap-2 mt-1">
                            <span className="text-sm text-muted-foreground">
                              {course?.title || "알 수 없는 과정"}
                            </span>
                            <span className="text-xs text-muted-foreground">•</span>
                            <span className="text-sm text-muted-foreground flex items-center">
                              <Clock className="w-3 h-3 mr-1" />
                              {formatDuration(video.durationSec)}
                            </span>
                            <span className="text-xs text-muted-foreground">•</span>
                            <span className="text-sm text-muted-foreground flex items-center">
                              <Calendar className="w-3 h-3 mr-1" />
                              {new Date(video.createdAt).toLocaleDateString()}
                            </span>
                          </div>
                        </div>
                      </div>

                      <div className="flex items-center space-x-4">
                        <Badge className={accessStatus.color} variant="secondary">
                          {accessStatus.label}
                        </Badge>

                        <div className="flex items-center space-x-2">
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => openEditDialog(video)}
                            data-testid={`button-edit-${video.id}`}
                          >
                            <Edit className="w-4 h-4 mr-1" />
                            편집
                          </Button>
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => openDeleteDialog(video)}
                            data-testid={`button-delete-${video.id}`}
                          >
                            <Trash2 className="w-4 h-4 mr-1" />
                            삭제
                          </Button>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Create/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={closeDialog}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto" data-testid="dialog-video-form">
          <DialogHeader>
            <DialogTitle className="flex items-center">
              <Video className="mr-2 w-5 h-5" />
              {editingVideo ? "동영상 편집" : "새 동영상 추가"}
            </DialogTitle>
            <DialogDescription>
              {editingVideo ? "동영상 정보를 수정하세요." : "새로운 동영상을 등록하세요."}
            </DialogDescription>
          </DialogHeader>

          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="courseId"
                  render={({ field }) => (
                    <FormItem className="col-span-2">
                      <FormLabel>강의 과정 *</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger data-testid="select-course">
                            <SelectValue placeholder="강의 과정을 선택하세요" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          {courses.map((course) => (
                            <SelectItem key={course.id} value={course.id}>
                              {course.title}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="title"
                  render={({ field }) => (
                    <FormItem className="col-span-2">
                      <FormLabel>제목 *</FormLabel>
                      <FormControl>
                        <Input placeholder="동영상 제목을 입력하세요" {...field} data-testid="input-title" />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="description"
                  render={({ field }) => (
                    <FormItem className="col-span-2">
                      <FormLabel>설명</FormLabel>
                      <FormControl>
                        <Textarea 
                          placeholder="동영상에 대한 설명을 입력하세요" 
                          rows={3}
                          {...field} 
                          data-testid="textarea-description"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="externalUrl"
                  render={({ field }) => (
                    <FormItem className="col-span-2">
                      <FormLabel>동영상 URL *</FormLabel>
                      <FormControl>
                        <div className="relative">
                          <LinkIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                          <Input 
                            placeholder="https://example.com/video.mp4" 
                            className="pl-10"
                            {...field} 
                            data-testid="input-external-url"
                          />
                        </div>
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="durationSec"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>재생 시간 (초)</FormLabel>
                      <FormControl>
                        <Input 
                          type="number" 
                          placeholder="3600"
                          {...field}
                          onChange={(e) => field.onChange(e.target.value ? parseInt(e.target.value) : undefined)}
                          data-testid="input-duration"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="isPublished"
                  render={({ field }) => (
                    <FormItem className="flex items-center space-x-2">
                      <FormLabel>공개 상태</FormLabel>
                      <FormControl>
                        <Switch
                          checked={field.value}
                          onCheckedChange={field.onChange}
                          data-testid="switch-published"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="accessStart"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>접근 시작 시간</FormLabel>
                      <FormControl>
                        <Input 
                          type="datetime-local" 
                          {...field} 
                          data-testid="input-access-start"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="accessEnd"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>접근 종료 시간</FormLabel>
                      <FormControl>
                        <Input 
                          type="datetime-local" 
                          {...field} 
                          data-testid="input-access-end"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <DialogFooter>
                <Button type="button" variant="outline" onClick={closeDialog} data-testid="button-cancel">
                  <X className="mr-2 w-4 h-4" />
                  취소
                </Button>
                <Button 
                  type="submit" 
                  disabled={createMutation.isPending || updateMutation.isPending}
                  data-testid="button-save"
                >
                  <Save className="mr-2 w-4 h-4" />
                  {createMutation.isPending || updateMutation.isPending 
                    ? "저장 중..." 
                    : editingVideo ? "수정하기" : "생성하기"
                  }
                </Button>
              </DialogFooter>
            </form>
          </Form>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation Dialog */}
      <Dialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <DialogContent data-testid="dialog-delete">
          <DialogHeader>
            <DialogTitle className="flex items-center text-destructive">
              <Trash2 className="mr-2 w-5 h-5" />
              동영상 삭제
            </DialogTitle>
            <DialogDescription>
              {deletingVideo && (
                <>
                  <strong>{deletingVideo.title}</strong> 동영상을 정말 삭제하시겠습니까?
                  <br />이 작업은 되돌릴 수 없습니다.
                </>
              )}
            </DialogDescription>
          </DialogHeader>

          <DialogFooter>
            <Button 
              variant="outline" 
              onClick={() => setDeleteDialogOpen(false)}
              data-testid="button-cancel-delete"
            >
              취소
            </Button>
            <Button
              variant="destructive"
              onClick={() => deletingVideo && deleteMutation.mutate(deletingVideo.id)}
              disabled={deleteMutation.isPending}
              data-testid="button-confirm-delete"
            >
              <Trash2 className="mr-2 w-4 h-4" />
              {deleteMutation.isPending ? "삭제 중..." : "삭제하기"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

