import { useAuth } from "@/hooks/useAuth";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Link, useLocation } from "wouter";
import { BookOpen, Clock, Users, Trophy, Video, Calendar, ArrowLeft } from "lucide-react";

interface Course {
  id: string;
  title: string;
  description?: string;
  thumbnail?: string;
  tags: string[];
  order: number;
}

interface Notice {
  id: string;
  title: string;
  body: string;
  startsAt?: string;
  endsAt?: string;
  createdAt: string;
}

export default function Members() {
  const { user } = useAuth();
  const [, setLocation] = useLocation();

  const { data: courses = [], isLoading: coursesLoading } = useQuery<Course[]>({
    queryKey: ["/api/courses"],
  });

  const { data: notices = [], isLoading: noticesLoading } = useQuery<Notice[]>({
    queryKey: ["/api/notices"],
  });

  // 접근 권한 확인 - VERIFIED 사용자만 접근 가능
  if (!user || (user as any)?.role !== 'VERIFIED') {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <Card className="w-full max-w-md mx-4">
          <CardContent className="pt-6">
            <div className="text-center">
              <Trophy className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
              <h2 className="text-xl font-semibold text-foreground mb-2">
                인증회원 전용 서비스
              </h2>
              <p className="text-muted-foreground mb-4">
                이 페이지는 인증된 회원만 이용할 수 있습니다.
              </p>
              <div className="space-y-2">
                <Button onClick={() => setLocation('/')} className="w-full">
                  <ArrowLeft className="mr-2 h-4 w-4" />
                  메인으로 돌아가기
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      {/* Welcome Section */}
      <section className="bg-gradient-to-br from-primary/10 via-accent/5 to-background py-16">
        <div className="container mx-auto px-4">
          <div className="max-w-4xl mx-auto text-center">
            <h1 className="text-4xl lg:text-5xl font-bold text-foreground mb-6">
              안녕하세요, {(user as any)?.firstName || "회원"}님!
            </h1>
            <p className="text-xl text-muted-foreground mb-8">
              시대영재 온라인 강의에 오신 것을 환영합니다. 오늘도 영어 실력 향상을 위해 함께 노력해봐요.
            </p>

            <div className="flex items-center justify-center mb-8">
              <Badge className="text-lg px-4 py-2 bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200">
                <Trophy className="mr-2 h-4 w-4" />
                인증 회원
              </Badge>
            </div>
          </div>
        </div>
      </section>

      {/* Stats Section */}
      <section className="py-12 bg-muted/30">
        <div className="container mx-auto px-4">
          <div className="grid md:grid-cols-4 gap-6 max-w-4xl mx-auto">
            <Card className="text-center">
              <CardContent className="pt-6">
                <BookOpen className="h-8 w-8 text-primary mx-auto mb-2" />
                <div className="text-2xl font-bold text-foreground mb-1">
                  {courses.length}
                </div>
                <p className="text-sm text-muted-foreground">이용 가능한 강의</p>
              </CardContent>
            </Card>
            <Card className="text-center">
              <CardContent className="pt-6">
                <Video className="h-8 w-8 text-green-600 mx-auto mb-2" />
                <div className="text-2xl font-bold text-foreground mb-1">50+</div>
                <p className="text-sm text-muted-foreground">동영상 강의</p>
              </CardContent>
            </Card>
            <Card className="text-center">
              <CardContent className="pt-6">
                <Users className="h-8 w-8 text-purple-600 mx-auto mb-2" />
                <div className="text-2xl font-bold text-foreground mb-1">990</div>
                <p className="text-sm text-muted-foreground">수강생 커뮤니티</p>
              </CardContent>
            </Card>
            <Card className="text-center">
              <CardContent className="pt-6">
                <Clock className="h-8 w-8 text-orange-600 mx-auto mb-2" />
                <div className="text-2xl font-bold text-foreground mb-1">24/7</div>
                <p className="text-sm text-muted-foreground">언제든 수강 가능</p>
              </CardContent>
            </Card>
          </div>
        </div>
      </section>

      {/* Courses Section */}
      <section className="py-16">
        <div className="container mx-auto px-4">
          <div className="max-w-6xl mx-auto">
            <div className="text-center mb-12">
              <h2 className="text-3xl lg:text-4xl font-bold text-foreground mb-4">
                이용 가능한 강의
              </h2>
              <p className="text-lg text-muted-foreground">
                전문 강사진이 제작한 고품질 온라인 강의를 수강하세요
              </p>
            </div>

            {coursesLoading ? (
              <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                {[1, 2, 3].map((i) => (
                  <Card key={i} className="animate-pulse">
                    <div className="h-48 bg-muted rounded-t-lg"></div>
                    <CardHeader>
                      <div className="h-4 bg-muted rounded w-3/4"></div>
                      <div className="h-3 bg-muted rounded w-1/2"></div>
                    </CardHeader>
                  </Card>
                ))}
              </div>
            ) : courses.length > 0 ? (
              <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                {courses.map((course) => (
                  <Card key={course.id} className="hover:shadow-lg transition-shadow">
                    {course.thumbnail ? (
                      <div className="h-48 overflow-hidden rounded-t-lg">
                        <img
                          src={course.thumbnail}
                          alt={course.title}
                          className="w-full h-full object-cover hover:scale-105 transition-transform duration-300"
                        />
                      </div>
                    ) : (
                      <div className="h-48 bg-gradient-to-br from-primary/20 to-accent/20 rounded-t-lg flex items-center justify-center">
                        <Video className="h-12 w-12 text-primary" />
                      </div>
                    )}
                    <CardHeader>
                      <CardTitle className="text-lg">{course.title}</CardTitle>
                      {course.description && (
                        <p className="text-sm text-muted-foreground line-clamp-2">
                          {course.description}
                        </p>
                      )}
                      <div className="flex flex-wrap gap-1">
                        {course.tags.slice(0, 3).map((tag, index) => (
                          <Badge key={index} variant="secondary" className="text-xs">
                            {tag}
                          </Badge>
                        ))}
                      </div>
                    </CardHeader>
                    <CardContent>
                      <Button asChild className="w-full">
                        <Link href={`/courses/${course.id}`}>
                          <BookOpen className="mr-2 h-4 w-4" />
                          강의 보기
                        </Link>
                      </Button>
                    </CardContent>
                  </Card>
                ))}
              </div>
            ) : (
              <Card className="text-center py-12">
                <CardContent>
                  <BookOpen className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                  <h3 className="text-lg font-semibold text-foreground mb-2">
                    아직 등록된 강의가 없습니다
                  </h3>
                  <p className="text-muted-foreground">
                    곧 새로운 강의가 업데이트될 예정입니다.
                  </p>
                </CardContent>
              </Card>
            )}
          </div>
        </div>
      </section>

      {/* Notices Section */}
      {notices.length > 0 && (
        <section className="py-16 bg-muted/30">
          <div className="container mx-auto px-4">
            <div className="max-w-4xl mx-auto">
              <div className="text-center mb-12">
                <h2 className="text-3xl font-bold text-foreground mb-4">
                  학원 공지사항
                </h2>
                <p className="text-lg text-muted-foreground">
                  중요한 소식을 놓치지 마세요
                </p>
              </div>

              <div className="space-y-4">
                {notices.slice(0, 5).map((notice) => (
                  <Card key={notice.id}>
                    <CardHeader>
                      <div className="flex items-center justify-between">
                        <CardTitle className="text-lg">{notice.title}</CardTitle>
                        <div className="flex items-center text-sm text-muted-foreground">
                          <Calendar className="mr-1 h-4 w-4" />
                          {new Date(notice.createdAt).toLocaleDateString('ko-KR')}
                        </div>
                      </div>
                      <p className="text-muted-foreground">
                        {notice.body.length > 150 
                          ? `${notice.body.substring(0, 150)}...` 
                          : notice.body}
                      </p>
                    </CardHeader>
                  </Card>
                ))}
              </div>
            </div>
          </div>
        </section>
      )}
    </div>
  );
}

client/src/pages/simple-admin.tsx.content:
import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import { 
  CheckCircle, 
  XCircle, 
  Trash2, 
  Upload, 
  Plus, 
  User, 
  ImageIcon, 
  Video,
  LogOut
} from "lucide-react";

interface PendingUser {
  id: string;
  email: string;
  firstName: string;
  lastName: string;
  createdAt: string;
}

interface GalleryImage {
  id: string;
  imageUrl: string;
  title: string;
  description: string;
  isVisible: boolean;
}

interface VideoLink {
  id: string;
  title: string;
  videoUrl: string;
  description: string;
}

export default function SimpleAdmin() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState("");
  const [pendingUsers, setPendingUsers] = useState<PendingUser[]>([]);
  const [galleryImages, setGalleryImages] = useState<GalleryImage[]>([]);
  const [videoLinks, setVideoLinks] = useState<VideoLink[]>([]);
  const [loading, setLoading] = useState(false);
  const [newImage, setNewImage] = useState({ title: "", description: "", imageUrl: "" });
  const [newVideo, setNewVideo] = useState({ title: "", videoUrl: "", description: "" });
  const { toast } = useToast();

  useEffect(() => {
    // 페이지 로드시 자동 로그인 시도하지 않음 - 항상 비밀번호 요구
    checkAuth();
  }, []);

  const checkAuth = async () => {
    // dev_admin 쿠키가 있는지 확인만 함
    try {
      const res = await fetch('/api/simple/ping', { credentials: 'include' });
      if (res.ok) {
        setIsAuthenticated(true);
        loadData();
      }
    } catch (error) {
      // 인증 안됨 - 비밀번호 입력 필요
    }
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      const response = await fetch('/api/dev/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ password })
      });

      const data = await response.json();

      if (response.ok && data.success) {
        setIsAuthenticated(true);
        setPassword("");
        toast({
          title: "로그인 성공",
          description: "관리자 페이지에 접속했습니다.",
        });
        await loadData();
      } else {
        toast({
          title: "로그인 실패",
          description: "잘못된 비밀번호입니다.",
          variant: "destructive",
        });
        setPassword("");
      }
    } catch (error) {
      toast({
        title: "오류",
        description: "로그인 중 오류가 발생했습니다.",
        variant: "destructive",
      });
      setPassword("");
    }
  };

  const loadData = async () => {
    try {
      setLoading(true);

      // 대기 회원 로드
      const usersRes = await fetch('/api/simple/pending-users', { credentials: 'include' });
      if (usersRes.ok) {
        const users = await usersRes.json();
        setPendingUsers(users);
      }

      // 갤러리 로드
      const galleryRes = await fetch('/api/simple/gallery', { credentials: 'include' });
      if (galleryRes.ok) {
        const images = await galleryRes.json();
        setGalleryImages(images);
      }

      // 동영상 링크 로드
      const videosRes = await fetch('/api/simple/videos', { credentials: 'include' });
      if (videosRes.ok) {
        const videos = await videosRes.json();
        setVideoLinks(videos);
      }

    } catch (error) {
      console.error('데이터 로드 오류:', error);
      toast({
        title: "오류",
        description: "데이터를 불러오는 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const approveUser = async (userId: string) => {
    try {
      const res = await fetch('/api/simple/approve-user', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ userId, memo: '관리자 승인' })
      });

      if (res.ok) {
        toast({
          title: "승인 완료",
          description: "회원이 성공적으로 승인되었습니다.",
        });
        loadData();
      } else {
        throw new Error('승인 실패');
      }
    } catch (error) {
      toast({
        title: "오류",
        description: "회원 승인 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    }
  };

  const rejectUser = async (userId: string) => {
    try {
      const res = await fetch('/api/simple/reject-user', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ userId, memo: '관리자 거부' })
      });

      if (res.ok) {
        toast({
          title: "거부 완료",
          description: "회원 신청이 거부되었습니다.",
        });
        loadData();
      } else {
        throw new Error('거부 실패');
      }
    } catch (error) {
      toast({
        title: "오류",
        description: "회원 거부 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    }
  };

  const addImage = async () => {
    if (!newImage.title || !newImage.imageUrl) return;

    try {
      const res = await fetch('/api/simple/gallery', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify(newImage)
      });

      if (res.ok) {
        toast({
          title: "이미지 추가 완료",
          description: "갤러리에 이미지가 추가되었습니다.",
        });
        setNewImage({ title: "", description: "", imageUrl: "" });
        loadData();
      } else {
        throw new Error('이미지 추가 실패');
      }
    } catch (error) {
      toast({
        title: "오류",
        description: "이미지 추가 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    }
  };

  const addVideo = async () => {
    if (!newVideo.title || !newVideo.videoUrl) return;

    try {
      const res = await fetch('/api/simple/videos', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify(newVideo)
      });

      if (res.ok) {
        toast({
          title: "동영상 추가 완료",
          description: "동영상 링크가 추가되었습니다.",
        });
        setNewVideo({ title: "", videoUrl: "", description: "" });
        loadData();
      } else {
        throw new Error('동영상 추가 실패');
      }
    } catch (error) {
      toast({
        title: "오류",
        description: "동영상 추가 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    }
  };

  const logout = async () => {
    try {
      await fetch('/api/dev/logout', { method: 'POST', credentials: 'include' });
      setIsAuthenticated(false);
      setPassword("");
      toast({
        title: "로그아웃 완료",
        description: "관리자 세션이 종료되었습니다.",
      });
    } catch (error) {
      setIsAuthenticated(false);
      setPassword("");
    }
  };

  // 인증되지 않은 경우 비밀번호 입력 화면
  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="bg-white p-8 rounded-lg shadow-lg max-w-md w-full mx-4">
          <div className="text-center mb-6">
            <h1 className="text-2xl font-bold text-gray-900 mb-2">시대영재 학원</h1>
            <p className="text-gray-600">관리자 로그인</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <Label htmlFor="password">관리자 비밀번호</Label>
              <Input
                id="password"
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="비밀번호를 입력하세요"
                autoFocus
                required
                data-testid="input-admin-password"
              />
            </div>
            <Button type="submit" className="w-full" data-testid="button-admin-login">
              로그인
            </Button>
          </form>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="bg-white border-b">
        <div className="container mx-auto px-4 py-4 flex justify-between items-center">
          <h1 className="text-2xl font-bold text-gray-900">시대영재 학원 관리자</h1>
          <Button variant="outline" onClick={logout}>
            <LogOut className="w-4 h-4 mr-2" />
            로그아웃
          </Button>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        <Tabs defaultValue="users" className="space-y-6">
          <TabsList className="grid w-full grid-cols-3">
            <TabsTrigger value="users">
              <User className="w-4 h-4 mr-2" />
              회원 관리 ({pendingUsers.length})
            </TabsTrigger>
            <TabsTrigger value="gallery">
              <ImageIcon className="w-4 h-4 mr-2" />
              갤러리 관리 ({galleryImages.length})
            </TabsTrigger>
            <TabsTrigger value="videos">
              <Video className="w-4 h-4 mr-2" />
              동영상 관리 ({videoLinks.length})
            </TabsTrigger>
          </TabsList>

          <TabsContent value="users">
            <Card>
              <CardHeader>
                <CardTitle>가입 승인 대기 회원</CardTitle>
              </CardHeader>
              <CardContent>
                {pendingUsers.length === 0 ? (
                  <p className="text-gray-500 text-center py-8">대기 중인 회원이 없습니다.</p>
                ) : (
                  <div className="space-y-4">
                    {pendingUsers.map((user) => (
                      <div key={user.id} className="border rounded-lg p-4 flex justify-between items-center">
                        <div>
                          <h3 className="font-semibold">{user.firstName} {user.lastName}</h3>
                          <p className="text-sm text-gray-600">{user.email}</p>
                          <p className="text-xs text-gray-400">
                            가입일: {new Date(user.createdAt).toLocaleDateString('ko-KR')}
                          </p>
                        </div>
                        <div className="flex gap-2">
                          <Button size="sm" onClick={() => approveUser(user.id)} data-testid={`approve-${user.id}`}>
                            <CheckCircle className="w-4 h-4 mr-1" />
                            승인
                          </Button>
                          <Button size="sm" variant="destructive" onClick={() => rejectUser(user.id)} data-testid={`reject-${user.id}`}>
                            <XCircle className="w-4 h-4 mr-1" />
                            거부
                          </Button>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="gallery">
            <div className="space-y-6">
              <Card>
                <CardHeader>
                  <CardTitle>새 이미지 추가</CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <Label htmlFor="imageTitle">제목</Label>
                      <Input
                        id="imageTitle"
                        value={newImage.title}
                        onChange={(e) => setNewImage(prev => ({ ...prev, title: e.target.value }))}
                        placeholder="이미지 제목"
                        data-testid="input-image-title"
                      />
                    </div>
                    <div>
                      <Label htmlFor="imageUrl">이미지 URL</Label>
                      <Input
                        id="imageUrl"
                        value={newImage.imageUrl}
                        onChange={(e) => setNewImage(prev => ({ ...prev, imageUrl: e.target.value }))}
                        placeholder="https://example.com/image.jpg"
                        data-testid="input-image-url"
                      />
                    </div>
                  </div>
                  <div>
                    <Label htmlFor="imageDescription">설명</Label>
                    <Textarea
                      id="imageDescription"
                      value={newImage.description}
                      onChange={(e) => setNewImage(prev => ({ ...prev, description: e.target.value }))}
                      placeholder="이미지 설명"
                      data-testid="textarea-image-description"
                    />
                  </div>
                  <Button onClick={addImage} data-testid="button-add-image">
                    <Plus className="w-4 h-4 mr-2" />
                    이미지 추가
                  </Button>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle>갤러리 이미지 목록</CardTitle>
                </CardHeader>
                <CardContent>
                  {galleryImages.length === 0 ? (
                    <p className="text-gray-500 text-center py-8">등록된 이미지가 없습니다.</p>
                  ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                      {galleryImages.map((image) => (
                        <div key={image.id} className="border rounded-lg overflow-hidden">
                          <img 
                            src={image.imageUrl} 
                            alt={image.title}
                            className="w-full h-40 object-cover"
                            onError={(e) => {
                              (e.target as HTMLImageElement).src = '/placeholder-image.jpg';
                            }}
                          />
                          <div className="p-3">
                            <h4 className="font-semibold text-sm">{image.title}</h4>
                            <p className="text-xs text-gray-600 mt-1">{image.description}</p>
                            <Badge variant={image.isVisible ? "default" : "secondary"} className="mt-2">
                              {image.isVisible ? "표시됨" : "숨김"}
                            </Badge>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>
          </TabsContent>

          <TabsContent value="videos">
            <div className="space-y-6">
              <Card>
                <CardHeader>
                  <CardTitle>새 동영상 링크 추가</CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <Label htmlFor="videoTitle">제목</Label>
                      <Input
                        id="videoTitle"
                        value={newVideo.title}
                        onChange={(e) => setNewVideo(prev => ({ ...prev, title: e.target.value }))}
                        placeholder="동영상 제목"
                        data-testid="input-video-title"
                      />
                    </div>
                    <div>
                      <Label htmlFor="videoUrl">동영상 URL</Label>
                      <Input
                        id="videoUrl"
                        value={newVideo.videoUrl}
                        onChange={(e) => setNewVideo(prev => ({ ...prev, videoUrl: e.target.value }))}
                        placeholder="https://example.com/video.mp4"
                        data-testid="input-video-url"
                      />
                    </div>
                  </div>
                  <div>
                    <Label htmlFor="videoDescription">설명</Label>
                    <Textarea
                      id="videoDescription"
                      value={newVideo.description}
                      onChange={(e) => setNewVideo(prev => ({ ...prev, description: e.target.value }))}
                      placeholder="동영상 설명"
                      data-testid="textarea-video-description"
                    />
                  </div>
                  <Button onClick={addVideo} data-testid="button-add-video">
                    <Plus className="w-4 h-4 mr-2" />
                    동영상 추가
                  </Button>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle>등록된 동영상 링크</CardTitle>
                </CardHeader>
                <CardContent>
                  {videoLinks.length === 0 ? (
                    <p className="text-gray-500 text-center py-8">등록된 동영상이 없습니다.</p>
                  ) : (
                    <div className="space-y-4">
                      {videoLinks.map((video) => (
                        <div key={video.id} className="border rounded-lg p-4">
                          <h4 className="font-semibold">{video.title}</h4>
                          <p className="text-sm text-gray-600 mt-1">{video.description}</p>
                          <a 
                            href={video.videoUrl} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="text-blue-600 hover:underline text-sm mt-2 inline-block"
                          >
                            {video.videoUrl}
                          </a>
                        </div>
                      ))}
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>
          </TabsContent>
        </Tabs>
      </div>
    </div>
  );
}

