import React, { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Trash2, Edit, Plus, LogOut } from 'lucide-react';

// 관리자 대시보드 탭 컴포넌트들
const PendingMembers = () => {
  const [members, setMembers] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);

  const loadMembers = async () => {
    setLoading(true);
    try {
      console.log('🔍 쿠키 확인:', document.cookie);
      console.log('🚀 API 호출 시작: /api/admin/members?status=pending');

      const response = await fetch('/api/admin/members?status=pending', {
        credentials: 'include'
      });

      console.log('📡 응답 상태:', response.status, response.statusText);
      console.log('🍪 응답 헤더:', Object.fromEntries(response.headers.entries()));

      const data = await response.json();
      console.log('📄 응답 데이터:', data);

      if (data.ok) {
        setMembers(data.items || []);
        console.log('✅ 회원 로드 성공:', data.items?.length, '명');
      } else {
        console.error('❌ Failed to load members:', data.message);
        // 401 에러면 다시 로그인 페이지로
        if (response.status === 401) {
          alert('세션이 만료되었습니다. 다시 로그인해주세요.');
          window.location.href = '/_superadmin';
        }
      }
    } catch (error) {
      console.error('💥 Error loading members:', error);
    }
    setLoading(false);
  };

  const handleApprove = async (userId: string) => {
    try {
      const response = await fetch('/api/admin/approve-user', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ userId, memo: '관리자 승인' })
      });
      const data = await response.json();
      if (data.ok) {
        loadMembers(); // 목록 새로고침
      }
    } catch (error) {
      console.error('Error approving user:', error);
    }
  };

  const handleReject = async (userId: string) => {
    try {
      const response = await fetch('/api/admin/reject-user', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ userId, memo: '관리자 거부' })
      });
      const data = await response.json();
      if (data.ok) {
        loadMembers(); // 목록 새로고침
      }
    } catch (error) {
      console.error('Error rejecting user:', error);
    }
  };

  React.useEffect(() => {
    loadMembers();
  }, []);

  return (
    <div data-testid="pending-members" className="space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-semibold">대기중인 회원</h2>
        <Button onClick={loadMembers} disabled={loading} data-testid="button-refresh">
          {loading ? '로딩중...' : '새로고침'}
        </Button>
      </div>

      {loading ? (
        <p>로딩중...</p>
      ) : members.length === 0 ? (
        <p data-testid="text-no-members">대기중인 회원이 없습니다.</p>
      ) : (
        <div className="grid gap-4">
          {members.map((member) => (
            <Card key={member.id} data-testid={`card-member-${member.id}`}>
              <CardContent className="pt-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="font-medium" data-testid={`text-name-${member.id}`}>
                      {member.name}
                    </p>
                    <p className="text-sm text-muted-foreground" data-testid={`text-email-${member.id}`}>
                      {member.email}
                    </p>
                    <p className="text-xs text-muted-foreground">
                      가입일: {new Date(member.createdAt).toLocaleDateString()}
                    </p>
                  </div>
                  <div className="space-x-2">
                    <Button 
                      onClick={() => handleApprove(member.id)}
                      size="sm" 
                      data-testid={`button-approve-${member.id}`}
                    >
                      승인
                    </Button>
                    <Button 
                      onClick={() => handleReject(member.id)}
                      variant="destructive" 
                      size="sm"
                      data-testid={`button-reject-${member.id}`}
                    >
                      거부
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
};

const VideoManager = () => {
  const [videos, setVideos] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingVideo, setEditingVideo] = useState<any>(null);
  const [formData, setFormData] = useState({ title: '', type: 'youtube', url: '' });
  const [urlValidationError, setUrlValidationError] = useState('');

  const loadVideos = async () => {
    setLoading(true);
    try {
      const response = await fetch('/api/admin/videos', {
        credentials: 'include'
      });
      const data = await response.json();
      console.log('🎬 동영상 목록 로드:', data);
      if (response.ok) {
        setVideos(data || []);
      }
    } catch (error) {
      console.error('Error loading videos:', error);
    }
    setLoading(false);
  };

  // 🔍 프론트엔드 사전 검증 함수
  const validateUrl = (url: string, type: string): string => {
    if (!url) return '';

    if (url.length > 2000) {
      return 'URL이 너무 깁니다. 2000자 이하로 입력해주세요.';
    }

    if (type === 'youtube') {
      const youtubePatterns = [
        /youtu\.be\/[A-Za-z0-9_-]+/,
        /youtube\.com\/watch\?.*v=[A-Za-z0-9_-]+/,
        /youtube\.com\/embed\/[A-Za-z0-9_-]+/,
        /m\.youtube\.com\/watch\?.*v=[A-Za-z0-9_-]+/
      ];

      const isValidYoutube = youtubePatterns.some(pattern => pattern.test(url));
      if (!isValidYoutube) {
        return 'YouTube URL 형식이 올바르지 않습니다. youtu.be, youtube.com/watch?v=, 또는 youtube.com/embed 형식을 사용하세요.';
      }
    }

    if (type === 'nas') {
      if (!/^https?:\/\//i.test(url)) {
        return 'NAS URL은 http:// 또는 https://로 시작해야 합니다.';
      }

      const videoExtensions = /\.(mp4|webm|m4v|mov|avi|mkv|ogg|ogv)(\?.*)?$/i;
      if (!videoExtensions.test(url)) {
        if (!/\.[a-zA-Z0-9]+(\?.*)?$/.test(url)) {
          return '파일 확장자가 없습니다. .mp4, .webm 등의 확장자를 포함해주세요.';
        } else {
          return '지원되지 않는 비디오 형식입니다. mp4, webm, m4v, mov, avi, mkv, ogg, ogv 파일만 지원됩니다.';
        }
      }
    }

    return '';
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title || !formData.url || !formData.type) return;

    // 🔍 프론트엔드 사전 검증
    const validationError = validateUrl(formData.url, formData.type);
    if (validationError) {
      setUrlValidationError(validationError);
      alert(`URL 검증 실패: ${validationError}`);
      return;
    }

    setUrlValidationError('');

    try {
      console.log('🎬 새로운 동영상 폼 제출:', formData);

      const url = editingVideo 
        ? `/api/admin/videos/${editingVideo.id}`
        : '/api/admin/videos';
      const method = editingVideo ? 'PUT' : 'POST';

      const response = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify(formData)
      });

      console.log('📡 서버 응답 상태:', response.status);
      const data = await response.json();
      console.log('📄 서버 응답 데이터:', data);

      if (data.ok) {
        console.log('✅ 동영상 저장 성공!');
        alert(editingVideo ? '동영상이 수정되었습니다.' : '동영상이 추가되었습니다.');
        loadVideos(); // 목록 새로고침
        setDialogOpen(false);
        setEditingVideo(null);
        setFormData({ title: '', type: 'youtube', url: '' });
      } else {
        console.error('❌ 서버에서 오류 응답:', data);
        // 🎯 구체적인 에러 메시지 표시
        const errorMessage = data.message || '동영상 저장에 실패했습니다.';
        const errorCode = data.code || 'UNKNOWN_ERROR';
        alert(`${errorMessage} (코드: ${errorCode})`);
      }
    } catch (error) {
      console.error('💥 동영상 저장 에러:', error);
      alert('동영상 저장 중 오류가 발생했습니다.');
    }
  };

  // 🎯 간단한 제목 편집 (사용자 제안 방식)
  const handleEdit = (video: any) => {
    const newTitle = window.prompt('새로운 제목을 입력하세요:', video.title);
    if (newTitle && newTitle.trim() !== video.title) {
      handleSave(video.id, newTitle.trim());
    }
  };

  // URL 입력 시 실시간 검증
  const handleUrlChange = (newUrl: string) => {
    setFormData(prev => ({ ...prev, url: newUrl }));

    if (newUrl) {
      const error = validateUrl(newUrl, formData.type);
      setUrlValidationError(error);
    } else {
      setUrlValidationError('');
    }
  };

  // 🎯 삭제 (사용자 제안 방식 - JSON 파싱 보장)
  const handleDelete = async (videoId: string) => {
    if (!window.confirm('정말 삭제 하시겠습니까?')) return;

    const r = await fetch(`/api/admin/videos/${videoId}`, {
      method: 'DELETE', 
      credentials: 'include'
    });
    const d = await r.json();   // JSON 보장

    if (d.ok) {
      setVideos(videos.filter(v => v.id !== videoId));
    } else {
      alert('삭제 실패: ' + d.code);
    }
  };

  // 🎯 제목 수정 (사용자 제안 방식 - JSON 파싱 보장)
  const handleSave = async (videoId: string, newTitle: string) => {
    const r = await fetch(`/api/admin/videos/${videoId}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ title: newTitle })
    });
    const d = await r.json();   // 이제 항상 JSON

    if (d.ok) {
      setVideos(videos.map(v => v.id === videoId ? { ...v, title: newTitle } : v));
    } else {
      alert('저장 실패: ' + d.code);
    }
  };

  const openAddDialog = () => {
    setEditingVideo(null);
    setFormData({ title: '', type: 'youtube', url: '' });
    setDialogOpen(true);
  };

  React.useEffect(() => {
    loadVideos();
  }, []);

  return (
    <div data-testid="video-manager" className="space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-semibold">동영상 관리</h2>
        <div className="space-x-2">
          <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
            <DialogTrigger asChild>
              <Button onClick={openAddDialog} data-testid="button-add-video">
                <Plus className="w-4 h-4 mr-2" />
                동영상 추가
              </Button>
            </DialogTrigger>
            <DialogContent className="max-w-md">
              <DialogHeader>
                <DialogTitle>
                  {editingVideo ? '동영상 수정' : '동영상 추가'}
                </DialogTitle>
              </DialogHeader>
              <form onSubmit={handleSubmit} className="space-y-4">
                <div>
                  <Label htmlFor="title">제목 *</Label>
                  <Input
                    id="title"
                    value={formData.title}
                    onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                    required
                    data-testid="input-video-title"
                  />
                </div>
                <div>
                  <Label htmlFor="type">동영상 타입 *</Label>
                  <Select 
                    value={formData.type} 
                    onValueChange={(value) => setFormData({ ...formData, type: value })}
                  >
                    <SelectTrigger data-testid="select-video-type">
                      <SelectValue placeholder="타입 선택" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="youtube">YouTube</SelectItem>
                      <SelectItem value="nas">NAS 파일</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label htmlFor="url">동영상 URL *</Label>
                  <Input
                    id="url"
                    type="url"
                    value={formData.url}
                    onChange={(e) => handleUrlChange(e.target.value)}
                    required
                    placeholder={formData.type === 'youtube' ? 'https://youtu.be/...' : 'https://nas.domain.com/video.mp4'}
                    className={urlValidationError ? 'border-red-500' : ''}
                    data-testid="input-video-url"
                  />
                  {urlValidationError && (
                    <p className="mt-1 text-sm text-red-600" data-testid="text-url-error">
                      {urlValidationError}
                    </p>
                  )}
                </div>
                <div className="flex space-x-2 pt-4">
                  <Button type="submit" data-testid="button-save-video">
                    {editingVideo ? '수정' : '추가'}
                  </Button>
                  <Button 
                    type="button" 
                    variant="outline" 
                    onClick={() => setDialogOpen(false)}
                    data-testid="button-cancel-video"
                  >
                    취소
                  </Button>
                </div>
              </form>
            </DialogContent>
          </Dialog>

          <Button onClick={loadVideos} disabled={loading} data-testid="button-refresh-videos">
            {loading ? '로딩중...' : '새로고침'}
          </Button>
        </div>
      </div>

      {loading ? (
        <p>로딩중...</p>
      ) : videos.length === 0 ? (
        <p data-testid="text-no-videos">등록된 동영상이 없습니다.</p>
      ) : (
        <div className="grid gap-4">
          {videos.map((video) => (
            <Card key={video.id} data-testid={`card-video-${video.id}`}>
              <CardContent className="pt-6">
                <div className="flex items-center justify-between">
                  <div className="flex-1">
                    <p className="font-medium" data-testid={`text-video-title-${video.id}`}>
                      {video.title}
                    </p>
                    {video.description && (
                      <p className="text-sm text-muted-foreground mt-1">
                        {video.description}
                      </p>
                    )}
                    <p className="text-sm text-muted-foreground">
                      코스: {video.courseName}
                    </p>
                    <p className="text-xs text-muted-foreground">
                      URL: {video.videoUrl}
                    </p>
                  </div>
                  <div className="space-x-2 ml-4">
                    <Button 
                      variant="outline"
                      size="sm"
                      onClick={() => handleEdit(video)}
                      data-testid={`button-edit-video-${video.id}`}
                    >
                      <Edit className="w-4 h-4" />
                    </Button>
                    <Button 
                      variant="destructive"
                      size="sm"
                      onClick={() => handleDelete(video.id)}
                      data-testid={`button-delete-video-${video.id}`}
                    >
                      <Trash2 className="w-4 h-4" />
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
};

const ApprovedMembersTab = () => {
  const [q, setQ] = useState('');
  const [loading, setLoading] = useState(false);
  const [rows, setRows] = useState<any[]>([]);

  const load = async () => {
    setLoading(true);
    try {
      const r = await fetch(`/api/admin/members?status=verified&q=${encodeURIComponent(q)}`, {
        credentials: 'include'
      });
      const d = await r.json();
      setRows(d.items || []);
    } catch (error) {
      console.error('회원 목록 로드 에러:', error);
    }
    setLoading(false);
  };

  useEffect(() => { load(); }, []);

  const handleDelete = async (id: string) => {
    if (!window.confirm('정말 탈퇴 처리하시겠습니까?')) return;
    try {
      const r = await fetch(`/api/admin/members/${id}`, {
        method: 'DELETE', 
        credentials: 'include'
      });
      const d = await r.json();
      if (d.ok) {
        setRows(prev => prev.filter(m => m.id !== id));
      } else {
        alert('탈퇴 실패: ' + (d.code || 'UNKNOWN'));
      }
    } catch (error) {
      console.error('회원 삭제 에러:', error);
      alert('탈퇴 처리 중 오류가 발생했습니다.');
    }
  };

  return (
    <div className="space-y-4" data-testid="approved-members-tab">
      <div className="flex gap-2">
        <input
          value={q}
          onChange={e => setQ(e.target.value)}
          placeholder="이름/이메일 검색"
          className="border rounded px-3 py-2 w-full"
          data-testid="input-search-members"
        />
        <button 
          onClick={load} 
          className="px-4 py-2 rounded bg-blue-600 text-white hover:bg-blue-700"
          data-testid="button-search-members"
        >
          검색
        </button>
      </div>

      {loading ? (
        <div data-testid="loading-members">불러오는 중...</div>
      ) : rows.length === 0 ? (
        <div data-testid="no-members">승인된 회원이 없습니다.</div>
      ) : (
        <table className="w-full text-sm border-collapse border border-gray-300">
          <thead>
            <tr className="text-left border-b bg-gray-50">
              <th className="py-2 px-3 border">이름</th>
              <th className="py-2 px-3 border">이메일</th>
              <th className="py-2 px-3 border">상태</th>
              <th className="py-2 px-3 border w-28">작업</th>
            </tr>
          </thead>
          <tbody>
            {rows.map(m => (
              <tr key={m.id} className="border-b hover:bg-gray-50" data-testid={`member-row-${m.id}`}>
                <td className="py-2 px-3 border">
                  {[m.firstName, m.lastName].filter(Boolean).join(' ') || m.email}
                </td>
                <td className="py-2 px-3 border">{m.email}</td>
                <td className="py-2 px-3 border">
                  <span className="px-2 py-1 bg-green-100 text-green-800 rounded text-xs">
                    승인됨
                  </span>
                </td>
                <td className="py-2 px-3 border">
                  <button 
                    onClick={() => handleDelete(m.id)} 
                    className="px-3 py-1 rounded bg-red-600 text-white hover:bg-red-700 text-xs"
                    data-testid={`button-delete-${m.id}`}
                  >
                    탈퇴
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

const GalleryManager = () => {
  const [images, setImages] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingImage, setEditingImage] = useState<any>(null);
  const [formData, setFormData] = useState({ caption: '', imageUrl: '' });

  const loadImages = async () => {
    setLoading(true);
    try {
      const response = await fetch('/api/admin/gallery', {
        credentials: 'include'
      });
      const data = await response.json();
      if (data.ok) {
        setImages(data.items || []);
      }
    } catch (error) {
      console.error('Error loading gallery:', error);
    }
    setLoading(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.imageUrl) return;

    try {
      const url = editingImage 
        ? `/api/admin/gallery/${editingImage.id}`
        : '/api/admin/gallery';
      const method = editingImage ? 'PUT' : 'POST';

      const response = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify(formData)
      });

      const data = await response.json();
      if (data.ok) {
        loadImages(); // 목록 새로고침
        setDialogOpen(false);
        setEditingImage(null);
        setFormData({ caption: '', imageUrl: '' });
      }
    } catch (error) {
      console.error('Error saving image:', error);
    }
  };

  const handleEdit = (image: any) => {
    setEditingImage(image);
    setFormData({
      caption: image.caption || '',
      imageUrl: image.url
    });
    setDialogOpen(true);
  };

  const handleDelete = async (imageId: string) => {
    if (!confirm('정말 삭제하시겠습니까?')) return;

    try {
      const response = await fetch(`/api/admin/gallery/${imageId}`, {
        method: 'DELETE',
        credentials: 'include'
      });

      const data = await response.json();
      if (data.ok) {
        loadImages(); // 목록 새로고침
      }
    } catch (error) {
      console.error('Error deleting image:', error);
    }
  };

  const openAddDialog = () => {
    setEditingImage(null);
    setFormData({ caption: '', imageUrl: '' });
    setDialogOpen(true);
  };

  React.useEffect(() => {
    loadImages();
  }, []);

  return (
    <div data-testid="gallery-manager" className="space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-semibold">갤러리 관리</h2>
        <div className="space-x-2">
          <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
            <DialogTrigger asChild>
              <Button onClick={openAddDialog} data-testid="button-add-image">
                <Plus className="w-4 h-4 mr-2" />
                이미지 추가
              </Button>
            </DialogTrigger>
            <DialogContent className="max-w-md">
              <DialogHeader>
                <DialogTitle>
                  {editingImage ? '이미지 수정' : '이미지 추가'}
                </DialogTitle>
              </DialogHeader>
              <form onSubmit={handleSubmit} className="space-y-4">
                <div>
                  <Label htmlFor="imageUrl">이미지 URL *</Label>
                  <Input
                    id="imageUrl"
                    type="url"
                    value={formData.imageUrl}
                    onChange={(e) => setFormData({ ...formData, imageUrl: e.target.value })}
                    required
                    placeholder="https://example.com/image.jpg"
                    data-testid="input-image-url"
                  />
                </div>
                <div>
                  <Label htmlFor="caption">캡션</Label>
                  <Input
                    id="caption"
                    value={formData.caption}
                    onChange={(e) => setFormData({ ...formData, caption: e.target.value })}
                    placeholder="이미지 설명"
                    data-testid="input-image-caption"
                  />
                </div>
                <div className="flex space-x-2 pt-4">
                  <Button type="submit" data-testid="button-save-image">
                    {editingImage ? '수정' : '추가'}
                  </Button>
                  <Button 
                    type="button" 
                    variant="outline" 
                    onClick={() => setDialogOpen(false)}
                    data-testid="button-cancel-image"
                  >
                    취소
                  </Button>
                </div>
              </form>
            </DialogContent>
          </Dialog>

          <Button onClick={loadImages} disabled={loading} data-testid="button-refresh-gallery">
            {loading ? '로딩중...' : '새로고침'}
          </Button>
        </div>
      </div>

      {loading ? (
        <p>로딩중...</p>
      ) : images.length === 0 ? (
        <p data-testid="text-no-images">등록된 이미지가 없습니다.</p>
      ) : (
        <div className="grid gap-4 grid-cols-1 md:grid-cols-2 lg:grid-cols-3">
          {images.map((image) => (
            <Card key={image.id} data-testid={`card-image-${image.id}`}>
              <CardContent className="pt-6">
                <div className="relative">
                  <img 
                    src={image.url} 
                    alt={image.caption || 'Gallery image'} 
                    className="w-full h-48 object-cover rounded"
                    data-testid={`img-gallery-${image.id}`}
                  />
                  <div className="absolute top-2 right-2 space-x-1">
                    <Button 
                      variant="secondary"
                      size="sm"
                      onClick={() => handleEdit(image)}
                      data-testid={`button-edit-image-${image.id}`}
                    >
                      <Edit className="w-4 h-4" />
                    </Button>
                    <Button 
                      variant="destructive"
                      size="sm"
                      onClick={() => handleDelete(image.id)}
                      data-testid={`button-delete-image-${image.id}`}
                    >
                      <Trash2 className="w-4 h-4" />
                    </Button>
                  </div>
                </div>
                {image.caption && (
                  <p className="text-sm text-muted-foreground mt-2" data-testid={`text-caption-${image.id}`}>
                    {image.caption}
                  </p>
                )}
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
};

