import { useState } from 'react';
import { useLocation } from 'wouter';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';

export default function AdminLoginPage() {
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [, setLocation] = useLocation();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      console.log('🔐 로그인 시도 시작');

      const response = await fetch('/api/admin/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        credentials: 'include',
        body: JSON.stringify({ password }),
      });

      console.log('📡 로그인 응답 상태:', response.status);
      console.log('🍪 로그인 응답 헤더:', Object.fromEntries(response.headers.entries()));

      const data = await response.json();
      console.log('📄 로그인 응답 데이터:', data);

      if (data.ok) {
        console.log('✅ 로그인 성공! 쿠키 확인:', document.cookie);
        // 로그인 성공 - 관리자 대시보드로 이동
        setTimeout(() => {
          setLocation('/admin-dashboard');
        }, 100); // 쿠키 설정을 위한 짧은 지연
      } else {
        setError(data.message || '로그인에 실패했습니다.');
      }
    } catch (error) {
      console.error('💥 Login error:', error);
      setError('로그인 중 오류가 발생했습니다.');
    }

    setLoading(false);
  };

  return (
    <div className="min-h-screen bg-background flex items-center justify-center" data-testid="admin-login-page">
      <div className="w-full max-w-md">
        <Card>
          <CardHeader className="text-center">
            <CardTitle className="text-2xl font-bold" data-testid="text-login-title">
              관리자 로그인
            </CardTitle>
            <p className="text-muted-foreground">
              시대영재 학원 관리자 페이지
            </p>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <Input
                  type="password"
                  placeholder="관리자 비밀번호"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  disabled={loading}
                  data-testid="input-password"
                />
              </div>

              {error && (
                <p className="text-sm text-red-500 text-center" data-testid="text-error">
                  {error}
                </p>
              )}

              <Button 
                type="submit" 
                className="w-full" 
                disabled={loading}
                data-testid="button-login"
              >
                {loading ? '로그인 중...' : '로그인'}
              </Button>
            </form>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

